export interface GeoLocation {
  lat: number;
  lng: number;
}

export interface PlaceSource {
  uri: string;
  title: string;
}

export interface GroundingChunk {
  maps?: {
    sourceId?: string;
    title?: string;
    uri?: string;
    placeAnswerSources?: {
      reviewSnippets?: {
        content?: string;
      }[];
    }[];
  };
}

export type VisitStatus = 'pending' | 'visited' | 'skipped';

export interface CanvasStop extends PlaceSource {
  id: string;
  status: VisitStatus;
  notes: string;
  selected: boolean; 
  lat?: number; // Optional
  lng?: number; // Optional
}

export interface CanvasPlan {
  id: string;
  timestamp: number;
  industry: IndustryOption;
  customQuery?: string; // Added for custom search support
  markdownText: string;
  stops: CanvasStop[];
  isSaved?: boolean;
}

export type IndustryType = 'corporate' | 'industrial' | 'startup' | 'retail' | 'hospitality' | 'outsourcing' | 'education' | 'health' | 'custom';

export interface IndustryOption {
  id: IndustryType;
  label: string;
  query: string;
  icon: string;
}

import { GoogleGenAI, Tool } from "@google/genai";
import { GeoLocation, CanvasPlan, PlaceSource, CanvasStop, IndustryOption } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateCanvasRoute = async (
  location: GeoLocation,
  industry: IndustryOption,
  customQueryText?: string
): Promise<CanvasPlan> => {

  // Use custom query if provided, otherwise default to industry query
  const searchContext = customQueryText || industry.query;
  const categoryLabel = customQueryText || industry.label;

  // System Instruction in Indonesian for local context
  const systemInstruction = `
    Anda adalah Sales Manager B2B senior untuk Absenku.com.
    Tugas: Cari prospek bisnis nyata menggunakan Google Maps di sekitar lokasi user.

    CRITICAL INSTRUCTION:
    1. GUNAKAN TOOL 'googleMaps' untuk mencari lokasi. Jangan hanya memberikan saran teks.
    2. Cari 8-12 bisnis yang SANGAT RELEVAN dengan kata kunci: "${searchContext}".
    3. Filter: Prioritaskan bisnis yang memiliki kantor fisik atau operasional nyata.
    4. Berikan output teks dalam format Markdown yang berisi:
       - **Alasan**: Kenapa bisnis ini butuh aplikasi HR.
       - **Opening Pitch**: Satu kalimat pembuka yang spesifik untuk jenis bisnis ini.
  `;

  try {
    const tools: Tool[] = [{ googleMaps: {} }];

    const prompt = `
      Lokasi saya: ${location.lat}, ${location.lng}.
      Saya adalah sales yang sedang mencari klien baru.

      Tolong carikan daftar: ${categoryLabel}.
      Gunakan search query spesifik: "${searchContext}".

      Pilih tempat-tempat yang potensial untuk didatangi langsung (canvas).
      Untuk setiap tempat, berikan strategi pendekatan singkat.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        systemInstruction,
        tools,
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: location.lat,
              longitude: location.lng,
            },
          },
        },
      },
    });

    const markdownText = response.text || "Tidak ada strategi khusus yang tersedia, namun lokasi telah ditemukan.";

    // Extract places from grounding chunks
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const rawPlaces: PlaceSource[] = [];

    chunks.forEach((chunk) => {
      if (chunk.maps?.uri && chunk.maps?.title) {
        rawPlaces.push({
          uri: chunk.maps.uri,
          title: chunk.maps.title,
        });
      }
    });

    // Remove duplicates based on URI
    const uniquePlaces = Array.from(new Map(rawPlaces.map(item => [item.uri, item])).values());

    // Generate a safe unique ID
    const generateId = () => {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
      }
      return `plan-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    };

    // Transform to CanvasStop with state
    const stops: CanvasStop[] = uniquePlaces.map((place, index) => ({
      ...place,
      id: `stop-${Date.now()}-${index}-${Math.random().toString(36).substr(2, 5)}`,
      status: 'pending',
      notes: '',
      selected: true,
      lat: undefined, 
      lng: undefined
    }));

    if (stops.length === 0 && !response.text) {
       throw new Error("AI tidak dapat menemukan lokasi spesifik di peta. Coba perluas area atau ganti kata kunci.");
    }

    return {
      id: generateId(),
      timestamp: Date.now(),
      industry,
      customQuery: customQueryText,
      markdownText,
      stops,
      isSaved: false
    };

  } catch (error: any) {
    console.error("Error generating canvas route:", error);
    const msg = error?.message || "Terjadi kesalahan saat menghubungi AI.";
    throw new Error(msg);
  }
};

import React, { useState, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import { CanvasPlan, CanvasStop, VisitStatus, GeoLocation } from '../types';
import { RouteMap } from './RouteMap';
import { optimizeRoute } from '../services/routeOptimization';
import { 
  MapPin, 
  Navigation, 
  CheckCircle2, 
  XCircle, 
  FileText, 
  ChevronDown, 
  Briefcase,
  Lightbulb,
  Archive,
  Trash2,
  ArrowLeft,
  Save,
  Map as MapIcon,
  CheckSquare,
  RefreshCw,
  AlertCircle,
  Share2,
  Send
} from 'lucide-react';

interface PlanDisplayProps {
  plan: CanvasPlan;
  onUpdateStop: (stopId: string, updates: Partial<CanvasStop>) => void;
  onUpdatePlanStops: (newStops: CanvasStop[]) => void;
  onComplete: () => void;
  onDelete: () => void;
  onSave?: () => void;
  onBack?: () => void;
  readOnly?: boolean;
  userLocation?: GeoLocation;
}

export const PlanDisplay: React.FC<PlanDisplayProps> = ({ 
  plan, 
  onUpdateStop, 
  onUpdatePlanStops,
  onComplete, 
  onDelete,
  onSave,
  onBack,
  readOnly = false,
  userLocation
}) => {
  const [activeTab, setActiveTab] = useState<'route' | 'map' | 'strategy'>('route');
  const [expandedStopId, setExpandedStopId] = useState<string | null>(null);

  useEffect(() => {
    if (plan.stops.length === 0 && plan.markdownText) {
      setActiveTab('strategy');
    }
  }, [plan.stops.length, plan.markdownText]);

  const selectedStops = plan.stops.filter(s => s.selected);
  const completedCount = selectedStops.filter(s => s.status !== 'pending').length;
  const totalSelected = selectedStops.length;
  const progress = totalSelected > 0 ? Math.round((completedCount / totalSelected) * 100) : 0;
  const isComplete = totalSelected > 0 && completedCount === totalSelected;

  const toggleStop = (id: string) => {
    setExpandedStopId(expandedStopId === id ? null : id);
  };

  const handleStatusChange = (stopId: string, status: VisitStatus) => {
    if (readOnly) return;
    onUpdateStop(stopId, { status });
  };

  const handleNotesChange = (stopId: string, notes: string) => {
    if (readOnly) return;
    onUpdateStop(stopId, { notes });
  };

  const handleSelectionToggle = (stopId: string) => {
    if (readOnly) return;
    const stop = plan.stops.find(s => s.id === stopId);
    if (stop) {
      onUpdateStop(stopId, { selected: !stop.selected });
    }
  };

  const handleOptimize = () => {
    if (userLocation && !readOnly) {
      const optimized = optimizeRoute(userLocation, plan.stops);
      onUpdatePlanStops(optimized);
      setActiveTab('map');
    }
  };

  const handleShareReport = () => {
    const date = new Date(plan.timestamp).toLocaleDateString();
    const target = plan.customQuery || plan.industry.label;

    let report = `*LAPORAN CANVAS PRO*\n`;
    report += `📅 Tanggal: ${date}\n`;
    report += `🎯 Target: ${target}\n`;
    report += `📊 Progress: ${completedCount}/${totalSelected} (${progress}%)\n\n`;
    report += `*DETAIL KUNJUNGAN:*\n`;

    selectedStops.forEach((stop, idx) => {
      const statusIcon = stop.status === 'visited' ? '✅' : stop.status === 'skipped' ? '⛔' : '⏳';
      report += `${idx + 1}. ${stop.title} ${statusIcon}\n`;
      if (stop.status !== 'pending' && stop.notes) {
        report += `   📝 Note: ${stop.notes}\n`;
      }
    });

    report += `\n_Generated by CanvasPro App_`;

    const url = `https://wa.me/?text=${encodeURIComponent(report)}`;
    window.open(url, '_blank');
  };

  return (
    <div className="animate-fade-in pb-20">

      {/* Dashboard Header */}
      <div className="bg-white rounded-2xl p-5 shadow-sm border border-slate-100 mb-6">
        <div className="flex flex-col gap-4 mb-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              {!readOnly && onBack && (
                <button 
                  onClick={onBack}
                  className="p-2 -ml-2 text-slate-400 hover:text-brand-600 hover:bg-slate-50 rounded-full transition-colors"
                >
                  <ArrowLeft className="w-6 h-6" />
                </button>
              )}
              <div>
                <h2 className="text-xl font-bold text-slate-800 leading-tight">
                  {plan.customQuery ? `"${plan.customQuery}"` : plan.industry?.label}
                </h2>
                <p className="text-xs text-slate-500 mt-1 flex items-center gap-2">
                  {new Date(plan.timestamp).toLocaleDateString()}
                  {plan.isSaved && <span className="text-brand-600 bg-brand-50 px-2 py-0.5 rounded font-bold text-[10px] uppercase border border-brand-100">Saved</span>}
                </p>
              </div>
            </div>

             {readOnly && (
               <button 
                 onClick={handleShareReport}
                 className="p-2 bg-green-50 text-green-600 rounded-full hover:bg-green-100 transition-colors"
                 title="Share Report via WhatsApp"
               >
                 <Share2 className="w-5 h-5" />
               </button>
            )}
          </div>

          {!readOnly && (
            <div className="flex gap-2 justify-between items-center border-t border-slate-50 pt-3">
               <div className="flex gap-2">
                <button 
                  onClick={onDelete}
                  className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors flex items-center gap-1 text-xs font-medium"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
               </div>

               <div className="flex gap-2">
                  {onSave && !plan.isSaved && (
                    <button 
                      onClick={onSave}
                      className="flex items-center gap-1.5 px-3 py-2 bg-white border border-slate-200 text-slate-600 text-xs font-bold rounded-lg hover:border-brand-300 hover:text-brand-600 transition-colors"
                    >
                      <Save className="w-4 h-4" />
                      Save
                    </button>
                  )}
                  <button 
                    onClick={onComplete}
                    className={`flex items-center gap-1.5 px-4 py-2 text-xs font-bold rounded-lg shadow-sm transition-all ${
                      isComplete 
                        ? 'bg-green-600 text-white hover:bg-green-700 shadow-green-200 animate-pulse' 
                        : 'bg-brand-600 text-white hover:bg-brand-700 shadow-brand-200'
                    }`}
                  >
                    <Archive className="w-4 h-4" />
                    {isComplete ? 'Finish & Report' : 'Finish'}
                  </button>
               </div>
            </div>
          )}
        </div>

        {/* Progress Bar */}
        <div className="space-y-2">
          <div className="flex justify-between text-sm font-medium">
            <span className="text-slate-600 text-xs uppercase tracking-wide">Progress Harian</span>
            <span className={isComplete ? "text-green-600" : "text-brand-700"}>{completedCount}/{totalSelected} Selesai</span>
          </div>
          <div className="h-2.5 w-full bg-slate-100 rounded-full overflow-hidden relative">
             <div className="absolute inset-0 bg-slate-100 w-full h-full opacity-50" style={{backgroundImage: 'linear-gradient(45deg,rgba(255,255,255,.15) 25%,transparent 25%,transparent 50%,rgba(255,255,255,.15) 50%,rgba(255,255,255,.15) 75%,transparent 75%,transparent)', backgroundSize: '1rem 1rem'}}></div>
            <div 
              className={`h-full transition-all duration-500 ease-out ${readOnly ? 'bg-slate-400' : isComplete ? 'bg-green-500' : 'bg-brand-500'}`}
              style={{ width: `${progress}%` }}
            />
          </div>
        </div>
      </div>

      {/* Navigation Tabs */}
      <div className="flex gap-2 mb-6 p-1 bg-slate-200/50 rounded-xl sticky top-20 z-10 backdrop-blur-sm">
        <button
          onClick={() => setActiveTab('route')}
          className={`flex-1 py-2 text-xs font-semibold rounded-lg flex items-center justify-center gap-1.5 transition-all ${
            activeTab === 'route' 
              ? 'bg-white text-brand-700 shadow-sm' 
              : 'text-slate-500 hover:text-slate-700'
          }`}
        >
          <MapPin className="w-4 h-4" />
          List
        </button>
        <button
          onClick={() => setActiveTab('map')}
          className={`flex-1 py-2 text-xs font-semibold rounded-lg flex items-center justify-center gap-1.5 transition-all ${
            activeTab === 'map' 
              ? 'bg-white text-brand-700 shadow-sm' 
              : 'text-slate-500 hover:text-slate-700'
          }`}
        >
          <MapIcon className="w-4 h-4" />
          Peta
        </button>
        <button
          onClick={() => setActiveTab('strategy')}
          className={`flex-1 py-2 text-xs font-semibold rounded-lg flex items-center justify-center gap-1.5 transition-all ${
            activeTab === 'strategy' 
              ? 'bg-white text-brand-700 shadow-sm' 
              : 'text-slate-500 hover:text-slate-700'
          }`}
        >
          <Lightbulb className="w-4 h-4" />
          Strategi
        </button>
      </div>

      {/* Content Area */}
      {activeTab === 'strategy' && (
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 animate-in fade-in slide-in-from-bottom-2">
          <div className="flex items-center gap-2 mb-4 pb-4 border-b border-slate-100">
             <div className="bg-yellow-100 p-2 rounded-lg text-yellow-600">
                <Lightbulb className="w-5 h-5" />
             </div>
             <div>
                <h3 className="font-bold text-slate-800">AI Sales Briefing</h3>
                <p className="text-xs text-slate-500">Strategi pendekatan khusus untuk kategori ini</p>
             </div>
          </div>
          <div className="prose prose-slate prose-sm prose-headings:text-brand-700 prose-a:text-brand-600 max-w-none">
            <ReactMarkdown>{String(plan.markdownText || 'Tidak ada briefing tersedia.')}</ReactMarkdown>
          </div>
        </div>
      )}

      {activeTab === 'map' && (
        <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2">
          {userLocation ? (
             <RouteMap stops={plan.stops} userLocation={userLocation} />
          ) : (
            <div className="p-8 text-center text-slate-500 bg-white rounded-2xl border border-dashed">
              Lokasi dibutuhkan untuk melihat peta.
            </div>
          )}

          {!readOnly && (
            <button 
              onClick={handleOptimize}
              disabled={plan.stops.length === 0}
              className="w-full py-3 bg-white border border-brand-200 text-brand-600 font-bold rounded-xl shadow-sm hover:bg-brand-50 flex items-center justify-center gap-2 disabled:opacity-50"
            >
              <RefreshCw className="w-4 h-4" />
              Optimasi Rute (TSP)
            </button>
          )}
        </div>
      )}

      {activeTab === 'route' && (
        <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2">

           {!readOnly && (
             <div className="flex justify-between items-center px-2 mb-2">
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">
                   {totalSelected} target lokasi hari ini
                </p>
             </div>
           )}

          {plan.stops.length === 0 ? (
            <div className="text-center p-8 bg-white rounded-2xl border border-dashed border-slate-300">
              <div className="inline-flex p-3 bg-slate-50 rounded-full mb-3 text-slate-400">
                <AlertCircle className="w-6 h-6" />
              </div>
              <h3 className="text-sm font-bold text-slate-700 mb-1">Lokasi Tidak Ditemukan</h3>
              <p className="text-xs text-slate-500 mb-4">
                Maps tidak menemukan bisnis spesifik di area ini. Gunakan panduan strategi AI untuk mencari manual.
              </p>
              <button 
                onClick={() => setActiveTab('strategy')}
                className="text-xs font-bold text-brand-600 bg-brand-50 px-4 py-2 rounded-lg hover:bg-brand-100 transition-colors"
              >
                Lihat Strategi AI
              </button>
            </div>
          ) : (
            plan.stops.map((stop, idx) => (
              <div 
                key={stop.id}
                className={`bg-white rounded-2xl shadow-sm border transition-all duration-300 overflow-hidden ${
                  stop.status === 'visited' ? 'border-brand-200 bg-brand-50/20' : 
                  stop.status === 'skipped' ? 'border-slate-100 opacity-60 bg-slate-50' :
                  !stop.selected ? 'border-slate-100 bg-slate-50 opacity-60 grayscale-[0.5]' :
                  'border-slate-200 hover:border-brand-300'
                }`}
              >
                {/* Card Header */}
                <div className="p-4">
                  <div className="flex justify-between items-start gap-3">
                    {/* Checklist & Title */}
                    <div className="flex items-start gap-3 flex-1">
                      {!readOnly && (
                        <button
                          onClick={() => handleSelectionToggle(stop.id)}
                          className={`mt-1 transition-colors hover:bg-slate-100 rounded p-0.5 ${stop.selected ? 'text-brand-600' : 'text-slate-300'}`}
                          title={stop.selected ? "Hapus dari rute" : "Tambah ke rute"}
                        >
                          <CheckSquare className="w-5 h-5" />
                        </button>
                      )}

                      <div 
                        className="flex-1 cursor-pointer"
                        onClick={() => toggleStop(stop.id)}
                      >
                        <div className="flex items-center gap-2 mb-1">
                          <span className={`inline-flex items-center justify-center w-6 h-6 rounded-full text-xs font-bold ${
                            stop.status === 'visited' ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-500'
                          }`}>
                            {idx + 1}
                          </span>
                          <h3 className={`font-bold text-lg leading-tight ${stop.status === 'visited' ? 'text-green-800 line-through decoration-2 decoration-green-300' : 'text-slate-800'}`}>
                            {stop.title}
                          </h3>
                        </div>
                        <p className="text-xs text-slate-400 pl-8 flex items-center gap-1">
                          <Briefcase className="w-3 h-3" />
                          {plan.customQuery || plan.industry?.label || "Lead"}
                        </p>
                      </div>
                    </div>

                    {/* Quick Actions */}
                    <div className="flex gap-2">
                       <a 
                        href={stop.uri}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="p-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-100 transition-colors"
                        title="Buka di Google Maps"
                      >
                        <Navigation className="w-5 h-5" />
                      </a>
                    </div>
                  </div>

                  {/* Status Toggles - Only active if not readOnly */}
                  {!readOnly && stop.selected && (
                    <div className="mt-4 flex items-center gap-2 pl-11">
                      <button
                        onClick={() => handleStatusChange(stop.id, 'visited')}
                        className={`flex-1 flex items-center justify-center gap-1.5 py-2 px-3 rounded-lg text-sm font-bold border transition-all ${
                          stop.status === 'visited' 
                            ? 'bg-green-100 border-green-200 text-green-700 shadow-inner' 
                            : 'bg-white border-slate-200 text-slate-500 hover:bg-green-50 hover:text-green-600 hover:border-green-200'
                        }`}
                      >
                        <CheckCircle2 className="w-4 h-4" />
                        Done
                      </button>
                      <button
                        onClick={() => handleStatusChange(stop.id, 'skipped')}
                        className={`flex-1 flex items-center justify-center gap-1.5 py-2 px-3 rounded-lg text-sm font-bold border transition-all ${
                          stop.status === 'skipped' 
                            ? 'bg-slate-100 border-slate-200 text-slate-600 shadow-inner' 
                            : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'
                        }`}
                      >
                        <XCircle className="w-4 h-4" />
                        Skip
                      </button>
                    </div>
                  )}

                  {!readOnly && stop.selected && (
                     <div className="mt-2 pl-11 flex justify-center">
                        <button
                           onClick={() => toggleStop(stop.id)}
                           className={`p-1 rounded-full text-slate-300 hover:text-slate-500 transition-transform duration-200 ${expandedStopId === stop.id ? 'rotate-180' : ''}`}
                        >
                           <ChevronDown className="w-5 h-5" />
                        </button>
                     </div>
                  )}
                </div>

                {/* Expanded Notes Section */}
                {(expandedStopId === stop.id || stop.notes) && stop.selected && (
                  <div className={`px-4 pb-4 pt-0 pl-11 ${expandedStopId === stop.id ? 'block' : 'hidden'}`}>
                    <div className="mt-2 space-y-2 border-t border-slate-100 pt-3">
                       <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider flex items-center gap-1">
                         <FileText className="w-3 h-3" />
                         Hasil Kunjungan / Catatan
                       </label>
                       {readOnly ? (
                          <div className="p-3 rounded-xl bg-slate-50 border border-slate-200 text-sm text-slate-700 min-h-[40px]">
                            {stop.notes || "Tidak ada catatan."}
                          </div>
                       ) : (
                          <textarea
                            value={stop.notes}
                            onChange={(e) => handleNotesChange(stop.id, e.target.value)}
                            placeholder="Contoh: Bertemu HRD Pak Budi, minta dihubungi besok..."
                            className="w-full p-3 rounded-xl bg-yellow-50/50 border border-yellow-100 text-sm focus:ring-2 focus:ring-brand-500 focus:outline-none min-h-[80px] placeholder:text-slate-400"
                          />
                       )}
                    </div>
                  </div>
                )}
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  MapPin, 
  Building2, 
  Briefcase, 
  Coffee, 
  Factory, 
  Zap, 
  Target, 
  AlertTriangle, 
  Users,
  GraduationCap,
  Stethoscope,
  RefreshCw,
  FolderOpen,
  ArrowRight,
  ArrowLeft,
  Trash2,
  Search,
  Sparkles
} from 'lucide-react';
import { GeoLocation, CanvasPlan, IndustryOption, CanvasStop } from './types';
import { generateCanvasRoute } from './services/geminiService';
import { PlanDisplay } from './components/PlanDisplay';
import { LoadingState } from './components/LoadingState';
import { BottomNav } from './components/BottomNav';
import { HistoryView } from './components/HistoryView';
import { SettingsView } from './components/SettingsView';

// Optimized queries for Google Maps Search (shorter, more keyword-focused)
const INDUSTRY_OPTIONS: IndustryOption[] = [
