          >
            <ArrowLeft className="w-4 h-4" /> Kembali ke History
          </button>
          <PlanDisplay 
            plan={selectedHistoryPlan} 
            onUpdateStop={() => {}} 
            onUpdatePlanStops={() => {}}
            onComplete={() => {}} 
            onDelete={() => {}}
            readOnly={true} 
            userLocation={location || undefined}
          />
        </div>
      );
    }

    // 2. Settings View
    if (currentView === 'settings') {
       return <SettingsView onClearHistory={handleClearHistory} onClearSaved={handleClearSaved} />;
    }

    // 3. Main Active/Create View
    if (currentView === 'active') {
      if (generating) return <LoadingState />;

      if (activePlan) {
        return (
          <PlanDisplay 
            plan={activePlan} 
            onUpdateStop={handleUpdateStop}
            onUpdatePlanStops={handleUpdatePlanStops}
            onComplete={handleCompleteRun}
            onDelete={handleDeleteActive}
            onSave={handleSaveRoute}
            onBack={handleBackFromActive}
            readOnly={false}
            userLocation={location || undefined}
