          </div>

          <div className="bg-white p-5 rounded-2xl shadow-sm border border-slate-200 mb-6 relative overflow-hidden">
             {/* Decorative BG */}
             <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none">
                <Target className="w-24 h-24" />
             </div>

             <label className="block text-sm font-bold text-slate-800 mb-4 flex items-center gap-2">
                <Target className="w-4 h-4 text-brand-600" />
                Pilih Target Industri
             </label>

             {/* Custom Search Field */}
             <div className="mb-4 relative">
                <input 
                  type="text"
                  value={customSearchTerm}
                  onChange={(e) => {
                     setCustomSearchTerm(e.target.value);
                     // If user types, we deselect the standard industry visually (logic handled in generate)
                  }}
                  placeholder="Ketik spesifik (Misal: Toko Bangunan, Dealer Motor)"
                  className="w-full pl-10 pr-4 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:border-brand-500 focus:ring-2 focus:ring-brand-100 outline-none text-sm transition-all"
                />
