                  >
                    <div className={selectedIndustry.id === opt.id && !customSearchTerm ? 'text-brand-600' : 'text-slate-400'}>
                      {getIcon(opt.icon)}
                    </div>
                    <span className="text-xs font-semibold leading-tight">
                      {opt.label}
                    </span>
                  </button>
                ))}
             </div>

             {customSearchTerm && (
                <div className="mt-3 text-center">
                   <p className="text-[10px] text-brand-600 font-medium flex items-center justify-center gap-1 animate-pulse">
                      <Sparkles className="w-3 h-3" />
                      Mode Pencarian Kustom Aktif
