              <div className={`p-2 rounded-full ${locError ? 'bg-red-100 text-red-600' : 'bg-brand-100 text-brand-600'}`}>
                {locError ? <AlertTriangle className="w-5 h-5" /> : <MapPin className="w-5 h-5" />}
              </div>
              <div className="flex-1">
                <p className="text-xs text-slate-400 font-bold uppercase tracking-wider">Lokasi Anda</p>
                {loadingLoc ? (
                  <p className="text-sm text-slate-500 animate-pulse">Sedang mencari lokasi...</p>
                ) : locError ? (
                  <p className="text-sm text-red-600 font-medium">{String(locError)}</p>
                ) : (
                  <p className="text-sm font-bold text-slate-800">
                    {location?.lat.toFixed(4)}, {location?.lng.toFixed(4)}
