          {activePlan && currentView === 'active' && !generating && (
            <div className="text-[10px] font-bold bg-green-100 text-green-700 px-3 py-1 rounded-full border border-green-200 flex items-center gap-1 uppercase tracking-wide">
              <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
              Live Session
            </div>
          )}
        </div>
      </header>

      <main className="max-w-2xl mx-auto px-4 py-6">
        {error && (
           <div className="mb-6 p-4 bg-red-50 text-red-600 rounded-xl border border-red-100 text-center text-sm font-medium animate-in fade-in flex items-center justify-center gap-2">
            <AlertTriangle className="w-4 h-4" />
            {String(error)}
          </div>
        )}

        {renderContent()}
      </main>

      <BottomNav 
        currentView={currentView} 
        onNavigate={(view) => {
          setCurrentView(view);
          setSelectedHistoryPlan(null);
