import { CanvasStop, GeoLocation } from "../types";

// Moved outside to ensure it is available to all functions
const deg2rad = (deg: number) => {
  return deg * (Math.PI / 180);
};

export const calculateDistance = (p1: GeoLocation, p2: GeoLocation): number => {
  const R = 6371; // Radius of the earth in km
  const dLat = deg2rad(p2.lat - p1.lat);
  const dLng = deg2rad(p2.lng - p1.lng);
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(deg2rad(p1.lat)) * Math.cos(deg2rad(p2.lat)) *
    Math.sin(dLng / 2) * Math.sin(dLng / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  const d = R * c; // Distance in km
  return d;
};

// Helper to generate deterministic mock coordinates if real ones are missing
export const generateMockCoordinates = (center: GeoLocation, index: number, total: number): GeoLocation => {
  // Create a spiral pattern or random scatter around center
  const radius = 0.005 + ((index % 5) * 0.002); // approx 0.5-2km
  const angle = (index / (total || 1)) * 2 * Math.PI;
  return {
    lat: center.lat + radius * Math.cos(angle),
    lng: center.lng + radius * Math.sin(angle)
  };
};

// Simple Nearest Neighbor TSP Algorithm
export const optimizeRoute = (
  startLocation: GeoLocation, 
  stops: CanvasStop[]
): CanvasStop[] => {
  // 1. Filter only selected stops
  const selectedStops = stops.filter(s => s.selected);
  const unselectedStops = stops.filter(s => !s.selected);

  if (selectedStops.length === 0) return stops;

  // 2. Prepare stops with coordinates (mock if necessary)
  const stopsWithCoords = selectedStops.map((stop, idx) => {
    // We calculate coords but DO NOT mutate the original object structure permanently with _temp
    const coords = (stop.lat !== undefined && stop.lng !== undefined) 
      ? { lat: stop.lat, lng: stop.lng } 
      : generateMockCoordinates(startLocation, idx, selectedStops.length);
    // Explicitly cast to any to attach temp prop for internal calculation only
    return { ...stop, _tempCoords: coords } as CanvasStop & { _tempCoords: GeoLocation }; 
  });

  const optimized: CanvasStop[] = [];
  const visited = new Set<string>();

  let currentLocation = startLocation;

  // 3. Greedy loop
  while (optimized.length < stopsWithCoords.length) {
    let nearestDist = Infinity;
    let nearestIdx = -1;

    for (let i = 0; i < stopsWithCoords.length; i++) {
      if (!visited.has(stopsWithCoords[i].id)) {
        const dist = calculateDistance(currentLocation, stopsWithCoords[i]._tempCoords);
        if (dist < nearestDist) {
          nearestDist = dist;
          nearestIdx = i;
        }
      }
    }

    if (nearestIdx !== -1) {
      const bestStop = stopsWithCoords[nearestIdx];
      visited.add(bestStop.id);

      // Clean up the temporary property before returning to state to prevent [object Object] errors
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { _tempCoords, ...cleanStop } = bestStop;
      optimized.push(cleanStop as CanvasStop);

      currentLocation = bestStop._tempCoords;
    } else {
      break;
    }
  }

  // 4. Return optimized sequence + unselected at the end
  return [...optimized, ...unselectedStops];
};

/**
 * Generates a Google Maps Directions URL with multiple waypoints.
 * Constraints: Google Maps usually handles up to 9 waypoints + origin/destination.
 */
export const generateGoogleMapsUrl = (origin: GeoLocation, stops: CanvasStop[]): string => {
  // 1. Filter only selected stops that have valid coordinates
  // We rely on the stops ALREADY being optimized/sorted before calling this function
  const validStops = stops.filter(s => s.selected && s.lat && s.lng);

  if (validStops.length === 0) return '';

  // 2. Define Origin
  const originStr = `${origin.lat},${origin.lng}`;

  // 3. Define Destination (The last stop in the optimized list)
  const lastStop = validStops[validStops.length - 1];
  const destinationStr = `${lastStop.lat},${lastStop.lng}`;

  // 4. Define Waypoints (All stops between origin and destination)
  // Google Maps format: waypoints=lat1,lng1|lat2,lng2|...
  const waypoints = validStops.slice(0, validStops.length - 1); // Exclude the last one (it's the destination)

  let url = `https://www.google.com/maps/dir/?api=1&origin=${originStr}&destination=${destinationStr}`;

  if (waypoints.length > 0) {
    const waypointsStr = waypoints
      .map(s => `${s.lat},${s.lng}`)
      .join('|');
    url += `&waypoints=${waypointsStr}`;
  }

  // Add travel mode
  url += `&travelmode=driving`;

  return url;
};

