import { GoogleGenAI, Tool } from "@google/genai";
import { GeoLocation, CanvasPlan, PlaceSource, CanvasStop, IndustryOption } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateCanvasRoute = async (
  location: GeoLocation,
  industry: IndustryOption,
  customQueryText?: string
): Promise<CanvasPlan> => {

  // Use custom query if provided, otherwise default to industry query
  const searchContext = customQueryText || industry.query;
  const categoryLabel = customQueryText || industry.label;

  // System Instruction in Indonesian for local context
  const systemInstruction = `
    Anda adalah Sales Manager B2B senior untuk Absenku.com.
    Tugas: Cari prospek bisnis nyata menggunakan Google Maps di sekitar lokasi user.

    CRITICAL INSTRUCTION:
    1. GUNAKAN TOOL 'googleMaps' untuk mencari lokasi. Jangan hanya memberikan saran teks.
    2. Cari 8-12 bisnis yang SANGAT RELEVAN dengan kata kunci: "${searchContext}".
    3. Filter: Prioritaskan bisnis yang memiliki kantor fisik atau operasional nyata.
    4. Berikan output teks dalam format Markdown yang berisi:
       - **Alasan**: Kenapa bisnis ini butuh aplikasi HR.
       - **Opening Pitch**: Satu kalimat pembuka yang spesifik untuk jenis bisnis ini.
  `;

  try {
    const tools: Tool[] = [{ googleMaps: {} }];

    const prompt = `
      Lokasi saya: ${location.lat}, ${location.lng}.
      Saya adalah sales yang sedang mencari klien baru.

      Tolong carikan daftar: ${categoryLabel}.
      Gunakan search query spesifik: "${searchContext}".

      Pilih tempat-tempat yang potensial untuk didatangi langsung (canvas).
      Untuk setiap tempat, berikan strategi pendekatan singkat.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        systemInstruction,
        tools,
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: location.lat,
              longitude: location.lng,
            },
          },
        },
      },
    });

    const markdownText = response.text || "Tidak ada strategi khusus yang tersedia, namun lokasi telah ditemukan.";

    // Extract places from grounding chunks
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const rawPlaces: PlaceSource[] = [];

    chunks.forEach((chunk) => {
      if (chunk.maps?.uri && chunk.maps?.title) {
        rawPlaces.push({
          uri: chunk.maps.uri,
          title: chunk.maps.title,
        });
      }
    });

    // Remove duplicates based on URI
    const uniquePlaces = Array.from(new Map(rawPlaces.map(item => [item.uri, item])).values());

    // Generate a safe unique ID
    const generateId = () => {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
      }
      return `plan-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    };

    // Transform to CanvasStop with state and ATTEMPT TO EXTRACT COORDS
    const stops: CanvasStop[] = uniquePlaces.map((place, index) => {
      let lat: number | undefined;
      let lng: number | undefined;

      // Try to extract coordinates from Google Maps URI
      // Typical format: /@(-6.123,106.123), or /@(-6.123,106.123,15z)/
      try {
        const match = place.uri.match(/@(-?\d+\.\d+),(-?\d+\.\d+)/);
        if (match) {
          lat = parseFloat(match[1]);
          lng = parseFloat(match[2]);
        }
      } catch (e) {
        // Ignore extraction errors
      }

      return {
        ...place,
        id: `stop-${Date.now()}-${index}-${Math.random().toString(36).substr(2, 5)}`,
        status: 'pending',
        notes: '',
        selected: true,
        lat, 
        lng
      };
    });

    if (stops.length === 0 && !response.text) {
       throw new Error("AI tidak dapat menemukan lokasi spesifik di peta. Coba perluas area atau ganti kata kunci.");
    }

    return {
      id: generateId(),
      timestamp: Date.now(),
      industry,
      customQuery: customQueryText,
      markdownText,
      stops,
      isSaved: false
    };

  } catch (error: any) {
    console.error("Error generating canvas route:", error);
    const msg = error?.message || "Terjadi kesalahan saat menghubungi AI.";
    throw new Error(msg);
  }
};

import { CanvasStop, GeoLocation } from "../types";

// Moved outside to ensure it is available to all functions
const deg2rad = (deg: number) => {
  return deg * (Math.PI / 180);
};

export const calculateDistance = (p1: GeoLocation, p2: GeoLocation): number => {
  const R = 6371; // Radius of the earth in km
  const dLat = deg2rad(p2.lat - p1.lat);
  const dLng = deg2rad(p2.lng - p1.lng);
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(deg2rad(p1.lat)) * Math.cos(deg2rad(p2.lat)) *
    Math.sin(dLng / 2) * Math.sin(dLng / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  const d = R * c; // Distance in km
  return d;
};

// Helper to generate deterministic mock coordinates if real ones are missing
export const generateMockCoordinates = (center: GeoLocation, index: number, total: number): GeoLocation => {
  // Create a spiral pattern or random scatter around center
  const radius = 0.005 + ((index % 5) * 0.002); // approx 0.5-2km
  const angle = (index / (total || 1)) * 2 * Math.PI;
  return {
    lat: center.lat + radius * Math.cos(angle),
    lng: center.lng + radius * Math.sin(angle)
  };
};

// Simple Nearest Neighbor TSP Algorithm
export const optimizeRoute = (
  startLocation: GeoLocation, 
  stops: CanvasStop[]
): CanvasStop[] => {
  // 1. Filter only selected stops
  const selectedStops = stops.filter(s => s.selected);
  const unselectedStops = stops.filter(s => !s.selected);

  if (selectedStops.length === 0) return stops;

  // 2. Prepare stops with coordinates (mock if necessary)
  const stopsWithCoords = selectedStops.map((stop, idx) => {
    // We calculate coords but DO NOT mutate the original object structure permanently with _temp
    const coords = (stop.lat !== undefined && stop.lng !== undefined) 
      ? { lat: stop.lat, lng: stop.lng } 
      : generateMockCoordinates(startLocation, idx, selectedStops.length);
    // Explicitly cast to any to attach temp prop for internal calculation only
    return { ...stop, _tempCoords: coords } as CanvasStop & { _tempCoords: GeoLocation }; 
  });

  const optimized: CanvasStop[] = [];
  const visited = new Set<string>();

  let currentLocation = startLocation;

  // 3. Greedy loop
  while (optimized.length < stopsWithCoords.length) {
    let nearestDist = Infinity;
    let nearestIdx = -1;

    for (let i = 0; i < stopsWithCoords.length; i++) {
      if (!visited.has(stopsWithCoords[i].id)) {
        const dist = calculateDistance(currentLocation, stopsWithCoords[i]._tempCoords);
        if (dist < nearestDist) {
          nearestDist = dist;
          nearestIdx = i;
        }
      }
    }

    if (nearestIdx !== -1) {
      const bestStop = stopsWithCoords[nearestIdx];
      visited.add(bestStop.id);

      // Clean up the temporary property before returning to state to prevent [object Object] errors
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { _tempCoords, ...cleanStop } = bestStop;
      optimized.push(cleanStop as CanvasStop);

      currentLocation = bestStop._tempCoords;
    } else {
      break;
    }
  }

  // 4. Return optimized sequence + unselected at the end
  return [...optimized, ...unselectedStops];
};

/**
 * Generates a Google Maps Directions URL with multiple waypoints.
 * 
 * ROBUSTNESS IMPROVEMENTS:
 * 1. Falls back to Place Title if lat/lng is missing.
 * 2. Limits to 10 stops (Google Maps URL limit for waypoints is 9 + origin/dest).
 */
export const generateGoogleMapsUrl = (origin: GeoLocation, stops: CanvasStop[]): string => {
  // 1. Filter only selected stops
  const validStops = stops.filter(s => s.selected);

  if (validStops.length === 0) return '';

  // 2. Limit to avoid URL overflow (Google Maps supports ~10 stops including origin/dest)
  // We take the first 10 stops from the optimized list to form a chain
  const stopsToNavigate = validStops.slice(0, 10);

  // 3. Define Origin
  const originStr = `${origin.lat},${origin.lng}`;

  // Helper to format waypoint
  const formatPoint = (s: CanvasStop) => {
    if (s.lat && s.lng) return `${s.lat},${s.lng}`;
    // Fallback to title. URL encoding handles most special chars.
    return encodeURIComponent(s.title);
  };

  // 4. Define Destination (The last stop in the chain)
  const lastStop = stopsToNavigate[stopsToNavigate.length - 1];
  const destinationStr = formatPoint(lastStop);

  // 5. Define Waypoints (Stops in between)
  const intermediateStops = stopsToNavigate.slice(0, stopsToNavigate.length - 1);

  let url = `https://www.google.com/maps/dir/?api=1&origin=${originStr}&destination=${destinationStr}`;

  if (intermediateStops.length > 0) {
    const waypointsStr = intermediateStops
      .map(formatPoint)
      .join('|');
    url += `&waypoints=${waypointsStr}`;
  }

  // Add travel mode
  url += `&travelmode=driving`;

  return url;
};

