interface PlanDisplayProps {
  plan: CanvasPlan;
  onUpdateStop: (stopId: string, updates: Partial<CanvasStop>) => void;
  onUpdatePlanStops: (newStops: CanvasStop[]) => void;
  onComplete: () => void;
  onDelete: () => void;
  onSave?: () => void;
  onBack?: () => void;
  readOnly?: boolean;
  userLocation?: GeoLocation;
}

export const PlanDisplay: React.FC<PlanDisplayProps> = ({ 
  plan, 
  onUpdateStop, 
  onUpdatePlanStops,
  onComplete, 
  onDelete,
  onSave,
  onBack,
  readOnly = false,
  userLocation
}) => {
  const [activeTab, setActiveTab] = useState<'route' | 'map' | 'strategy'>('route');
  const [expandedStopId, setExpandedStopId] = useState<string | null>(null);

  useEffect(() => {
    if (plan.stops.length === 0 && plan.markdownText) {
      setActiveTab('strategy');
    }
  }, [plan.stops.length, plan.markdownText]);

  const selectedStops = plan.stops.filter(s => s.selected);
  const completedCount = selectedStops.filter(s => s.status !== 'pending').length;
  const totalSelected = selectedStops.length;
  const progress = totalSelected > 0 ? Math.round((completedCount / totalSelected) * 100) : 0;
  const isComplete = totalSelected > 0 && completedCount === totalSelected;

  const toggleStop = (id: string) => {
    setExpandedStopId(expandedStopId === id ? null : id);
  };

  const handleStatusChange = (stopId: string, status: VisitStatus) => {
    if (readOnly) return;
    onUpdateStop(stopId, { status });
  };

  const handleNotesChange = (stopId: string, notes: string) => {
    if (readOnly) return;
    onUpdateStop(stopId, { notes });
  };

  const handleSelectionToggle = (stopId: string) => {
    if (readOnly) return;
    const stop = plan.stops.find(s => s.id === stopId);
    if (stop) {
      onUpdateStop(stopId, { selected: !stop.selected });
    }
  };

  const handleOptimize = (silent = false) => {
    if (userLocation && !readOnly) {
      const optimized = optimizeRoute(userLocation, plan.stops);
      onUpdatePlanStops(optimized);
      if (!silent) setActiveTab('map');
      return optimized; // Return for chaining
    }
    return plan.stops;
  };

  const handleStartSmartNavigation = () => {
    if (!userLocation) {
      alert("Lokasi Anda dibutuhkan untuk navigasi.");
      return;
    }

    if (totalSelected === 0) {
      alert("Pilih minimal satu lokasi untuk navigasi.");
      return;
    }

    // 1. Optimize the route first (reorder based on nearest neighbor)
    const optimizedStops = handleOptimize(true); // silent=true keeps user on current tab

    // 2. Generate the deep link URL based on the optimized order
    const url = generateGoogleMapsUrl(userLocation, optimizedStops);

    if (!url) {
      // This should rarely happen given our robust fallback logic
      alert("Gagal membuat link navigasi.");
      return;
    }

    // 3. Open Google Maps
    window.open(url, '_blank');
