      if (stop.status !== 'pending' && stop.notes) {
        report += `   📝 Note: ${stop.notes}\n`;
      }
    });

    report += `\n_Generated by CanvasPro App_`;

    const url = `https://wa.me/?text=${encodeURIComponent(report)}`;
    window.open(url, '_blank');
  };

