import { CanvasStop, GeoLocation } from "../types";

// Konversi derajat ke radian
const deg2rad = (deg: number) => {
  return deg * (Math.PI / 180);
};

// Menghitung jarak Haversine (km)
export const calculateDistance = (p1: GeoLocation, p2: GeoLocation): number => {
  const R = 6371; // Radius bumi km
  const dLat = deg2rad(p2.lat - p1.lat);
  const dLng = deg2rad(p2.lng - p1.lng);
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(deg2rad(p1.lat)) * Math.cos(deg2rad(p2.lat)) *
    Math.sin(dLng / 2) * Math.sin(dLng / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
};

// Generate koordinat mock deterministik jika lat/lng kosong
export const generateMockCoordinates = (center: GeoLocation, index: number, total: number): GeoLocation => {
  const radius = 0.005 + ((index % 5) * 0.002); 
  const angle = (index / (total || 1)) * 2 * Math.PI;
  return {
    lat: center.lat + radius * Math.cos(angle),
    lng: center.lng + radius * Math.sin(angle)
  };
};

/**
 * Menghitung total jarak rute dalam KM
 */
export const calculateTotalRouteDistance = (start: GeoLocation, stops: CanvasStop[], returnToStart: boolean = false): number => {
  if (stops.length === 0) return 0;

  let totalDist = 0;
  let current = start;

  // Jarak dari Start ke titik pertama
  // Dan titik ke titik berikutnya
  stops.forEach(stop => {
    if (stop.lat && stop.lng) {
      const stopLoc = { lat: stop.lat, lng: stop.lng };
      totalDist += calculateDistance(current, stopLoc);
      current = stopLoc;
    }
  });

  // Jika Round Trip, hitung jarak dari titik terakhir kembali ke Start
  if (returnToStart) {
    totalDist += calculateDistance(current, start);
  }

  return parseFloat(totalDist.toFixed(2));
};

/**
 * ALGORITMA TSP HYBRID:
 * 1. Nearest Neighbor (Inisialisasi Cepat)
 * 2. 2-Opt Local Search (Refinement untuk menghilangkan jalur menyilang)
 */
export const optimizeRoute = (
  startLocation: GeoLocation, 
  stops: CanvasStop[],
  returnToStart: boolean = false
): CanvasStop[] => {
  const selectedStops = stops.filter(s => s.selected);
  const unselectedStops = stops.filter(s => !s.selected);

  if (selectedStops.length <= 1) return stops;

  // 1. Siapkan data dengan koordinat valid (atau mock sementara untuk kalkulasi)
  // Kita pisahkan data untuk algoritma agar tidak mengotori object asli
  const points = selectedStops.map((stop, idx) => ({
    originalIndex: idx, // Melacak posisi di array selectedStops
    lat: stop.lat ?? generateMockCoordinates(startLocation, idx, selectedStops.length).lat,
    lng: stop.lng ?? generateMockCoordinates(startLocation, idx, selectedStops.length).lng,
    id: stop.id
  }));

  // --- PHASE 1: Nearest Neighbor Construction ---
  const tour: typeof points = [];
  const visited = new Set<string>();
  let currentLoc = startLocation;

  while (tour.length < points.length) {
    let nearestIdx = -1;
    let minDesc = Infinity;

    for (let i = 0; i < points.length; i++) {
      if (!visited.has(points[i].id)) {
        const dist = calculateDistance(currentLoc, points[i]);
        if (dist < minDesc) {
          minDesc = dist;
          nearestIdx = i;
        }
      }
    }

    if (nearestIdx !== -1) {
      visited.add(points[nearestIdx].id);
      tour.push(points[nearestIdx]);
      currentLoc = points[nearestIdx];
    } else {
      break;
    }
  }

  // --- PHASE 2: 2-Opt Optimization (Refinement) ---
  // Algoritma ini menukar edge (u, v) dan (x, y) menjadi (u, x) dan (v, y) jika jaraknya lebih pendek
  // Kita lakukan iterasi sampai tidak ada perbaikan (atau max iterasi untuk performa)

  let improved = true;
  const maxIterations = 50; // Safety break
  let iter = 0;

  // Helper untuk hitung total jarak tour saat ini
  const getTourDistance = (currentTour: typeof points): number => {
    let dist = calculateDistance(startLocation, currentTour[0]); // Start -> First
    for (let i = 0; i < currentTour.length - 1; i++) {
      dist += calculateDistance(currentTour[i], currentTour[i+1]);
    }
    if (returnToStart) {
      dist += calculateDistance(currentTour[currentTour.length - 1], startLocation); // Last -> Start
    }
    return dist;
  };

  while (improved && iter < maxIterations) {
    improved = false;
    iter++;

    // 2-Opt swap check
    for (let i = 0; i < tour.length - 1; i++) {
      for (let k = i + 1; k < tour.length; k++) {
        // Coba balikkan segmen dari i ke k
        const newTour = [...tour];
        // Reverse sub-array dari i ke k
        const segment = newTour.slice(i, k + 1).reverse();
        newTour.splice(i, segment.length, ...segment);

        if (getTourDistance(newTour) < getTourDistance(tour)) {
          tour.splice(0, tour.length, ...newTour); // Update tour
          improved = true;
        }
      }
    }
  }

  // --- Reconstruct Final Array ---
  const optimizedSelectedStops = tour.map(p => selectedStops[p.originalIndex]);

  return [...optimizedSelectedStops, ...unselectedStops];
};

/**
 * Generate Google Maps URL
 * Supports Round Trip (Start -> A -> B -> ... -> Start)
 */
export const generateGoogleMapsUrl = (
  origin: GeoLocation, 
  stops: CanvasStop[], 
  returnToStart: boolean = false
): string => {
  const validStops = stops.filter(s => s.selected);
  if (validStops.length === 0) return '';

  // Limit stops to 9 intermediate waypoints if using origin/dest structure carefully
  // Google maps supports approx 10 points total in standard dir URLs
  const stopsToNavigate = validStops.slice(0, 9); // Safety limit

  const originStr = `${origin.lat},${origin.lng}`;

  // Jika Round Trip: Destinasi adalah Origin
  // Jika One Way: Destinasi adalah titik terakhir
  const destinationStr = returnToStart 
    ? originStr 
    : (stopsToNavigate[stopsToNavigate.length - 1].lat && stopsToNavigate[stopsToNavigate.length - 1].lng)
      ? `${stopsToNavigate[stopsToNavigate.length - 1].lat},${stopsToNavigate[stopsToNavigate.length - 1].lng}`
      : encodeURIComponent(stopsToNavigate[stopsToNavigate.length - 1].title);

  // Waypoints
  // Jika Round Trip: Semua titik adalah waypoint
  // Jika One Way: Semua titik KECUALI yang terakhir adalah waypoint
  let waypointsList = returnToStart 
    ? stopsToNavigate 
    : stopsToNavigate.slice(0, stopsToNavigate.length - 1);

  let url = `https://www.google.com/maps/dir/?api=1&origin=${originStr}&destination=${destinationStr}`;

  if (waypointsList.length > 0) {
    const waypointsStr = waypointsList
      .map(s => (s.lat && s.lng) ? `${s.lat},${s.lng}` : encodeURIComponent(s.title))
      .join('|');
    url += `&waypoints=${waypointsStr}`;
  }

  url += `&travelmode=driving`;
  return url;
};

import React, { useState, useMemo } from 'react';
import { CanvasStop, GeoLocation } from '../types';
import { generateMockCoordinates } from '../services/routeOptimization';
import { MapPin, Navigation } from 'lucide-react';

interface RouteMapProps {
  stops: CanvasStop[];
  userLocation: GeoLocation;
  returnToStart?: boolean;
}

export const RouteMap: React.FC<RouteMapProps> = ({ stops, userLocation, returnToStart = false }) => {
  const [hoveredId, setHoveredId] = useState<string | null>(null);

  // Filter active stops
  const activeStops = stops.filter(s => s.selected);

  // Prepare points with valid coordinates
  const points = useMemo(() => {
    return [
      { id: 'start', lat: userLocation.lat, lng: userLocation.lng, label: 'Start', title: 'Lokasi Anda (Start)', isStart: true },
      ...activeStops.map((stop, i) => {
        const hasCoords = typeof stop.lat === 'number' && typeof stop.lng === 'number';
        const coords = hasCoords
          ? { lat: stop.lat!, lng: stop.lng! }
          : generateMockCoordinates(userLocation, i, activeStops.length);

        return { 
          id: stop.id, 
          lat: coords.lat,
          lng: coords.lng,
          label: String(i + 1),
          title: stop.title,
          isStart: false
        };
      })
    ];
  }, [activeStops, userLocation]);

  // Handle empty state
  if (activeStops.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-64 bg-slate-50 rounded-2xl border border-dashed border-slate-300">
        <MapPin className="w-8 h-8 text-slate-300 mb-2" />
        <p className="text-slate-400 text-sm">Pilih lokasi untuk melihat rute</p>
      </div>
    );
  }

  // --- Aspect Ratio & Normalization Logic ---
  const lats = points.map(p => p.lat);
  const lngs = points.map(p => p.lng);
  const minLat = Math.min(...lats);
  const maxLat = Math.max(...lats);
  const minLng = Math.min(...lngs);
  const maxLng = Math.max(...lngs);

  // Tambahkan padding 15% agar titik tidak menempel di pinggir
  const latSpan = maxLat - minLat || 0.005;
  const lngSpan = maxLng - minLng || 0.005;
  const paddingLat = latSpan * 0.15;
  const paddingLng = lngSpan * 0.15;

  // ViewBox calculation
  // Kita ingin memetakan koordinat bumi ke SVG 0-100 x 0-100 tapi mempertahankan rasio
  // Agar peta tidak "gepeng".
  const aspectRatio = (lngSpan + 2 * paddingLng) / (latSpan + 2 * paddingLat);

  // Tentukan dimensi SVG internal
  const svgHeight = 300;
  const svgWidth = svgHeight * aspectRatio; // Lebar menyesuaikan rasio asli bumi

  const normalize = (lat: number, lng: number) => {
    // X = Longitude (kiri ke kanan)
    const x = ((lng - (minLng - paddingLng)) / (lngSpan + 2 * paddingLng)) * svgWidth;
    // Y = Latitude (bawah ke atas, tapi SVG Y itu atas ke bawah, jadi perlu invert)
    const y = svgHeight - (((lat - (minLat - paddingLat)) / (latSpan + 2 * paddingLat)) * svgHeight);
    return { x, y };
  };

  const normalizedPoints = points.map(p => ({
    ...p,
    ...normalize(p.lat, p.lng)
  }));

  // Create Path String
  let pathD = `M ${normalizedPoints[0].x},${normalizedPoints[0].y}`;
  for (let i = 1; i < normalizedPoints.length; i++) {
    pathD += ` L ${normalizedPoints[i].x},${normalizedPoints[i].y}`;
  }
  // If round trip, close the path back to start
  if (returnToStart) {
    pathD += ` L ${normalizedPoints[0].x},${normalizedPoints[0].y}`;
  }

  return (
    <div className="relative w-full bg-slate-50 rounded-2xl border border-slate-200 overflow-hidden shadow-inner group">

      {/* Map Background Grid/Decoration */}
      <div className="absolute inset-0 opacity-10" 
           style={{ 
             backgroundImage: 'radial-gradient(#94a3b8 1px, transparent 1px)', 
             backgroundSize: '20px 20px' 
           }}>
      </div>

      <div className="absolute top-3 left-3 bg-white/90 backdrop-blur border border-slate-200 px-2 py-1 rounded-md shadow-sm z-10">
        <span className="text-[10px] font-bold text-slate-500 flex items-center gap-1">
          <Navigation className="w-3 h-3 text-brand-500" />
          OPTIMIZED MAP
        </span>
      </div>

      <div className="w-full overflow-x-auto overflow-y-hidden custom-scrollbar">
        <svg 
          height={svgHeight} 
          width={svgWidth} // Dynamic width based on aspect ratio
          className="mx-auto my-4"
          style={{ minWidth: '100%' }} // Ensure it fills container at minimum
        >
          <defs>
            <marker
              id="arrowhead"
              markerWidth="6"
              markerHeight="4"
              refX="8"
              refY="2"
              orient="auto"
            >
              <polygon points="0 0, 6 2, 0 4" fill="#94a3b8" />
            </marker>
          </defs>

          {/* Connection Lines */}
          <path
            d={pathD}
            fill="none"
            stroke="#cbd5e1"
            strokeWidth="3"
            strokeLinejoin="round"
            strokeLinecap="round"
          />

          {/* Animated Dash Overlay */}
          <path
            d={pathD}
            fill="none"
            stroke="#3b82f6"
            strokeWidth="1.5"
            strokeDasharray="6 4"
            markerMid="url(#arrowhead)" // Browser support varies for markerMid on paths, but useful where supported
            className="animate-[dash_30s_linear_infinite]"
          >
            <animate attributeName="stroke-dashoffset" from="100" to="0" dur="2s" repeatCount="indefinite" />
          </path>

          {/* Points */}
          {normalizedPoints.map((p, idx) => (
            <g 
              key={p.id}
              onMouseEnter={() => setHoveredId(p.id)}
              onMouseLeave={() => setHoveredId(null)}
              className="cursor-pointer transition-transform duration-200 hover:scale-110"
              style={{ transformBox: 'fill-box', transformOrigin: 'center' }}
            >
              {/* Pulse effect for hovered or start */}
              {(p.isStart || hoveredId === p.id) && (
                <circle 
                  cx={p.x} cy={p.y} r="8" 
                  fill={p.isStart ? "#ef4444" : "#3b82f6"} 
                  className="opacity-20 animate-ping" 
                />
              )}

              {/* Outer Ring */}
              <circle 
                cx={p.x} cy={p.y} r="6" 
                fill="white" 
                stroke={p.isStart ? "#ef4444" : hoveredId === p.id ? "#2563eb" : "#64748b"}
                strokeWidth="2"
              />

              {/* Inner Dot/Label */}
              {p.isStart ? (
                <circle cx={p.x} cy={p.y} r="2.5" fill="#ef4444" />
              ) : (
                <text 
                  x={p.x} y={p.y} 
                  dy=".3em" 
                  textAnchor="middle" 
                  fontSize="4" 
                  fontWeight="bold" 
                  fill={hoveredId === p.id ? "#2563eb" : "#64748b"}
                >
                  {p.label}
                </text>
              )}

              {/* Tooltip in SVG (ForeignObject is tricky, using React overlay instead for reliability) */}
            </g>
          ))}
        </svg>
      </div>

      {/* HTML Overlay Tooltip */}
      {hoveredId && (
        <div 
          className="absolute z-20 pointer-events-none bg-slate-900 text-white text-xs px-3 py-1.5 rounded-lg shadow-xl -translate-x-1/2 -translate-y-full whitespace-nowrap"
          style={{
            left: (normalizedPoints.find(p => p.id === hoveredId)?.x || 0) / svgWidth * 100 + '%',
            top: ((normalizedPoints.find(p => p.id === hoveredId)?.y || 0) / svgHeight * 100) + '%',
            marginTop: '-12px',
            marginLeft: '50%' // Correction because normalizedPoints x is in pixels relative to SVG width
          }}
        >
          {normalizedPoints.find(p => p.id === hoveredId)?.title}
          {/* Arrow down */}
          <div className="absolute left-1/2 -bottom-1 -translate-x-1/2 w-2 h-2 bg-slate-900 rotate-45"></div>
        </div>
      )}

      {/* Legend Footer */}
      <div className="bg-white border-t border-slate-100 p-3 flex justify-between items-center text-[10px] text-slate-500">
         <div className="flex gap-3">
           <div className="flex items-center gap-1">
             <span className="w-2 h-2 rounded-full border border-red-500 bg-red-500"></span> Start
           </div>
           <div className="flex items-center gap-1">
             <span className="w-2 h-2 rounded-full border border-slate-400 bg-white"></span> Stops
           </div>
         </div>
         {returnToStart && (
           <div className="flex items-center gap-1 text-brand-600 font-medium">
             <RefreshCwIcon className="w-3 h-3" /> Round Trip
           </div>
         )}
      </div>
    </div>
  );
};

const RefreshCwIcon = ({ className }: { className?: string }) => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}>
    <path d="M3 12a9 9 0 0 1 9-9 9.75 9.75 0 0 1 6.74 2.74L21 8" />
    <path d="M21 3v5h-5" />
    <path d="M21 12a9 9 0 0 1-9 9 9.75 9.75 0 0 1-6.74-2.74L3 16" />
    <path d="M3 21v-5h5" />
  </svg>
);

import React, { useState, useEffect, useMemo } from 'react';
import ReactMarkdown from 'react-markdown';
import { CanvasPlan, CanvasStop, VisitStatus, GeoLocation } from '../types';
import { RouteMap } from './RouteMap';
import { optimizeRoute, generateGoogleMapsUrl, calculateTotalRouteDistance } from '../services/routeOptimization';
import { 
  MapPin, 
  Navigation, 
  CheckCircle2, 
  XCircle, 
  FileText, 
  ChevronDown, 
  Briefcase,
  Lightbulb,
  Archive,
  Trash2,
  ArrowLeft,
  Save,
  Map as MapIcon,
  CheckSquare,
  Share2,
  ExternalLink,
  ListTodo,
  Repeat,
  ArrowRight
} from 'lucide-react';

interface PlanDisplayProps {
  plan: CanvasPlan;
  onUpdateStop: (stopId: string, updates: Partial<CanvasStop>) => void;
  onUpdatePlanStops: (newStops: CanvasStop[]) => void;
  onComplete: () => void;
  onDelete: () => void;
  onSave?: () => void;
  onBack?: () => void;
  readOnly?: boolean;
  userLocation?: GeoLocation;
}

export const PlanDisplay: React.FC<PlanDisplayProps> = ({ 
  plan, 
  onUpdateStop, 
  onUpdatePlanStops,
  onComplete, 
  onDelete,
  onSave,
  onBack,
  readOnly = false,
  userLocation
}) => {
  const [activeTab, setActiveTab] = useState<'route' | 'map' | 'strategy'>('route');
  const [expandedStopId, setExpandedStopId] = useState<string | null>(null);
  const [returnToStart, setReturnToStart] = useState(false); // Round Trip Toggle

  useEffect(() => {
    if (plan.stops.length === 0 && plan.markdownText) {
      setActiveTab('strategy');
    }
  }, [plan.stops.length, plan.markdownText]);

  const selectedStops = plan.stops.filter(s => s.selected);
  const completedCount = selectedStops.filter(s => s.status !== 'pending').length;
  const totalSelected = selectedStops.length;
  const totalStops = plan.stops.length;
  const progress = totalSelected > 0 ? Math.round((completedCount / totalSelected) * 100) : 0;
  const isComplete = totalSelected > 0 && completedCount === totalSelected;

  const allSelected = totalStops > 0 && totalSelected === totalStops;

  // Calculate estimated distance on the fly
  const estimatedTotalDistance = useMemo(() => {
    if (!userLocation) return 0;
    return calculateTotalRouteDistance(userLocation, selectedStops, returnToStart);
  }, [userLocation, selectedStops, returnToStart]);

  const toggleStop = (id: string) => {
    setExpandedStopId(expandedStopId === id ? null : id);
  };

  const handleStatusChange = (stopId: string, status: VisitStatus) => {
    if (readOnly) return;
    onUpdateStop(stopId, { status });
  };

  const handleNotesChange = (stopId: string, notes: string) => {
    if (readOnly) return;
    onUpdateStop(stopId, { notes });
  };

  const handleSelectionToggle = (stopId: string) => {
    if (readOnly) return;
    const stop = plan.stops.find(s => s.id === stopId);
    if (stop) {
      onUpdateStop(stopId, { selected: !stop.selected });
    }
  };

  const handleToggleAll = () => {
    if (readOnly) return;
    const newSelectionState = !allSelected;
    const newStops = plan.stops.map(stop => ({
      ...stop,
      selected: newSelectionState
    }));
    onUpdatePlanStops(newStops);
  };

  const handleOptimize = (silent = false) => {
    if (userLocation && !readOnly) {
      // Use the new 2-Opt Hybrid optimization
      const optimized = optimizeRoute(userLocation, plan.stops, returnToStart);
      onUpdatePlanStops(optimized);
      if (!silent) setActiveTab('map');
      return optimized;
    }
    return plan.stops;
  };

  const handleStartSmartNavigation = () => {
    if (!userLocation) {
      alert("Lokasi Anda dibutuhkan untuk navigasi.");
      return;
    }

    if (totalSelected === 0) {
      alert("Pilih minimal satu lokasi untuk navigasi.");
      return;
    }

    // 1. Optimize first to ensure order is correct
    const optimizedStops = handleOptimize(true); 

    // 2. Generate URL (supports Round Trip now)
    const url = generateGoogleMapsUrl(userLocation, optimizedStops, returnToStart);

    if (!url) {
      alert("Gagal membuat link navigasi.");
      return;
    }

    window.open(url, '_blank');
  };

  const handleShareReport = () => {
    const date = new Date(plan.timestamp).toLocaleDateString();
    const target = plan.customQuery || plan.industry.label;

    let report = `*LAPORAN CANVAS PRO*\n`;
    report += `📅 Tanggal: ${date}\n`;
    report += `🎯 Target: ${target}\n`;
    report += `📏 Estimasi Jarak: ${estimatedTotalDistance} km (${returnToStart ? 'PP' : 'One Way'})\n`;
    report += `📊 Progress: ${completedCount}/${totalSelected} (${progress}%)\n\n`;
    report += `*DETAIL KUNJUNGAN:*\n`;

    selectedStops.forEach((stop, idx) => {
      const statusIcon = stop.status === 'visited' ? '✅' : stop.status === 'skipped' ? '⛔' : '⏳';
      report += `${idx + 1}. ${stop.title} ${statusIcon}\n`;
      if (stop.status !== 'pending' && stop.notes) {
        report += `   📝 Note: ${stop.notes}\n`;
      }
    });

    report += `\n_Generated by CanvasPro App_`;

    const url = `https://wa.me/?text=${encodeURIComponent(report)}`;
    window.open(url, '_blank');
  };

  return (
    <div className="animate-fade-in pb-36">

      {/* Dashboard Header */}
      <div className="bg-white rounded-2xl p-5 shadow-sm border border-slate-100 mb-6">
        <div className="flex flex-col gap-4 mb-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              {!readOnly && onBack && (
                <button 
                  onClick={onBack}
                  className="p-2 -ml-2 text-slate-400 hover:text-brand-600 hover:bg-slate-50 rounded-full transition-colors"
                >
                  <ArrowLeft className="w-6 h-6" />
                </button>
              )}
              <div>
                <h2 className="text-xl font-bold text-slate-800 leading-tight">
                  {plan.customQuery ? `"${plan.customQuery}"` : plan.industry?.label}
                </h2>
                <p className="text-xs text-slate-500 mt-1 flex items-center gap-2">
                  {new Date(plan.timestamp).toLocaleDateString()}
                  {plan.isSaved && <span className="text-brand-600 bg-brand-50 px-2 py-0.5 rounded font-bold text-[10px] uppercase border border-brand-100">Saved</span>}
                </p>
              </div>
            </div>

             {readOnly && (
               <button 
                 onClick={handleShareReport}
                 className="p-2 bg-green-50 text-green-600 rounded-full hover:bg-green-100 transition-colors"
                 title="Share Report via WhatsApp"
               >
                 <Share2 className="w-5 h-5" />
               </button>
            )}
          </div>

          {!readOnly && (
            <div className="flex gap-2 justify-between items-center border-t border-slate-50 pt-3">
               <div className="flex gap-2">
                <button 
                  onClick={onDelete}
                  className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors flex items-center gap-1 text-xs font-medium"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
               </div>

               <div className="flex gap-2">
                  {onSave && !plan.isSaved && (
                    <button 
                      onClick={onSave}
                      className="flex items-center gap-1.5 px-3 py-2 bg-white border border-slate-200 text-slate-600 text-xs font-bold rounded-lg hover:border-brand-300 hover:text-brand-600 transition-colors"
                    >
                      <Save className="w-4 h-4" />
                      Save
                    </button>
                  )}
                  <button 
                    onClick={onComplete}
                    className={`flex items-center gap-1.5 px-4 py-2 text-xs font-bold rounded-lg shadow-sm transition-all ${
                      isComplete 
                        ? 'bg-green-600 text-white hover:bg-green-700 shadow-green-200 animate-pulse' 
                        : 'bg-brand-600 text-white hover:bg-brand-700 shadow-brand-200'
                    }`}
                  >
                    <Archive className="w-4 h-4" />
                    {isComplete ? 'Finish & Report' : 'Finish'}
                  </button>
               </div>
            </div>
          )}
        </div>

        {/* Progress Bar */}
        <div className="space-y-2">
          <div className="flex justify-between text-sm font-medium">
            <span className="text-slate-600 text-xs uppercase tracking-wide">Progress Harian</span>
            <span className={isComplete ? "text-green-600" : "text-brand-700"}>{completedCount}/{totalSelected} Selesai</span>
          </div>
          <div className="h-2.5 w-full bg-slate-100 rounded-full overflow-hidden relative">
             <div className="absolute inset-0 bg-slate-100 w-full h-full opacity-50" style={{backgroundImage: 'linear-gradient(45deg,rgba(255,255,255,.15) 25%,transparent 25%,transparent 50%,rgba(255,255,255,.15) 50%,rgba(255,255,255,.15) 75%,transparent 75%,transparent)', backgroundSize: '1rem 1rem'}}></div>
            <div 
              className={`h-full transition-all duration-500 ease-out ${readOnly ? 'bg-slate-400' : isComplete ? 'bg-green-500' : 'bg-brand-500'}`}
              style={{ width: `${progress}%` }}
            />
          </div>
        </div>
      </div>

      {/* Navigation Tabs */}
      <div className="flex gap-2 mb-6 p-1 bg-slate-200/50 rounded-xl sticky top-20 z-10 backdrop-blur-sm">
        <button
          onClick={() => setActiveTab('route')}
          className={`flex-1 py-2 text-xs font-semibold rounded-lg flex items-center justify-center gap-1.5 transition-all ${
            activeTab === 'route' 
              ? 'bg-white text-brand-700 shadow-sm' 
              : 'text-slate-500 hover:text-slate-700'
          }`}
        >
          <ListTodo className="w-4 h-4" />
          List
        </button>
        <button
          onClick={() => setActiveTab('map')}
          className={`flex-1 py-2 text-xs font-semibold rounded-lg flex items-center justify-center gap-1.5 transition-all ${
            activeTab === 'map' 
              ? 'bg-white text-brand-700 shadow-sm' 
              : 'text-slate-500 hover:text-slate-700'
          }`}
        >
          <MapIcon className="w-4 h-4" />
          Peta
        </button>
        <button
          onClick={() => setActiveTab('strategy')}
          className={`flex-1 py-2 text-xs font-semibold rounded-lg flex items-center justify-center gap-1.5 transition-all ${
            activeTab === 'strategy' 
              ? 'bg-white text-brand-700 shadow-sm' 
              : 'text-slate-500 hover:text-slate-700'
          }`}
        >
          <Lightbulb className="w-4 h-4" />
          Strategi
        </button>
      </div>

      {/* Content Area */}
      {activeTab === 'strategy' && (
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 animate-in fade-in slide-in-from-bottom-2">
          <div className="flex items-center gap-2 mb-4 pb-4 border-b border-slate-100">
             <div className="bg-yellow-100 p-2 rounded-lg text-yellow-600">
                <Lightbulb className="w-5 h-5" />
             </div>
             <div>
                <h3 className="font-bold text-slate-800">AI Sales Briefing</h3>
                <p className="text-xs text-slate-500">Strategi pendekatan khusus untuk kategori ini</p>
             </div>
          </div>
          <div className="prose prose-slate prose-sm prose-headings:text-brand-700 prose-a:text-brand-600 max-w-none">
            <ReactMarkdown>{String(plan.markdownText || 'Tidak ada briefing tersedia.')}</ReactMarkdown>
          </div>
        </div>
      )}

      {activeTab === 'map' && (
        <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2">
          {userLocation ? (
            <>
               <RouteMap stops={plan.stops} userLocation={userLocation} returnToStart={returnToStart} />

               {/* Distance Info Card */}
               <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex items-center justify-between">
                  <div>
                    <p className="text-xs text-slate-400 font-medium uppercase">Estimasi Jarak Tempuh</p>
                    <p className="text-lg font-bold text-slate-800">~{estimatedTotalDistance} km</p>
                  </div>
                  <div className="flex flex-col items-end">
                     <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold mb-1 ${returnToStart ? 'bg-brand-100 text-brand-600' : 'bg-slate-100 text-slate-500'}`}>
                        {returnToStart ? 'ROUND TRIP' : 'ONE WAY'}
                     </span>
                     <p className="text-[10px] text-slate-400">Jarak lurus (Haversine)</p>
                  </div>
               </div>
            </>
          ) : (
            <div className="p-8 text-center text-slate-500 bg-white rounded-2xl border border-dashed">
              Lokasi dibutuhkan untuk melihat peta.
            </div>
          )}
        </div>
      )}

      {activeTab === 'route' && (
        <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2">

           {!readOnly && (
             <div className="flex justify-between items-center px-2 mb-2 bg-slate-50/50 p-2 rounded-lg border border-slate-100/50">
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">
                   {totalSelected} target lokasi hari ini
