  const [history, setHistory] = useState<CanvasPlan[]>([]);
  const [savedRoutes, setSavedRoutes] = useState<CanvasPlan[]>([]);

  const [generating, setGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Load from Local Storage on mount
  useEffect(() => {
    try {
      const savedActive = localStorage.getItem(LOCAL_STORAGE_ACTIVE_KEY);
      if (savedActive) {
        setActivePlan(JSON.parse(savedActive));
      }

      const savedHistory = localStorage.getItem(LOCAL_STORAGE_HISTORY_KEY);
      if (savedHistory) {
        setHistory(JSON.parse(savedHistory));
      }

      const savedRoutesData = localStorage.getItem(LOCAL_STORAGE_SAVED_KEY);
      if (savedRoutesData) {
        setSavedRoutes(JSON.parse(savedRoutesData));
      }
    } catch (e) {
      console.error("Failed to load saved data", e);
    }
  }, []);

  // Save Active Plan
  useEffect(() => {
    if (activePlan) {
      localStorage.setItem(LOCAL_STORAGE_ACTIVE_KEY, JSON.stringify(activePlan));
    } else {
      localStorage.removeItem(LOCAL_STORAGE_ACTIVE_KEY);
    }
  }, [activePlan]);

  // Save History
  useEffect(() => {
    localStorage.setItem(LOCAL_STORAGE_HISTORY_KEY, JSON.stringify(history));
  }, [history]);

  // Save Routes (Drafts)
  useEffect(() => {
    localStorage.setItem(LOCAL_STORAGE_SAVED_KEY, JSON.stringify(savedRoutes));
  }, [savedRoutes]);

  const fetchLocation = useCallback(() => {
    setLoadingLoc(true);
    setLocError(null);

    if (!("geolocation" in navigator)) {
      setLocError("Geolocation not supported.");
      setLoadingLoc(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        setLocation({
          lat: position.coords.latitude,
          lng: position.coords.longitude,
        });
        setLoadingLoc(false);
        setLocError(null);
      },
      (err) => {
        console.error(err);
        setLocError("Location access denied.");
        setLoadingLoc(false);
      },
      {
        enableHighAccuracy: true,
        timeout: 10000,
        maximumAge: 0
      }
    );
  }, []);

  useEffect(() => {
    fetchLocation();
  }, [fetchLocation]);

  const handleGenerate = async () => {
    if (!location) {
      fetchLocation();
      return;
    }

    setGenerating(true);
    setError(null);

    try {
      // Pass the custom search term if it exists, otherwise undefined
      const result = await generateCanvasRoute(
        location, 
        selectedIndustry, 
        customSearchTerm.trim() !== '' ? customSearchTerm : undefined
      );
      setActivePlan(result);
      setCustomSearchTerm(''); // Reset after use
    } catch (e: any) {
      console.error("Generate error", e);
      let msg = "Gagal membuat rencana canvassing.";
      if (e instanceof Error) {
         msg = e.message;
      }
      setError(String(msg));
    } finally {
      setGenerating(false);
    }
  };

  const handleUpdateStop = (stopId: string, updates: Partial<CanvasStop>) => {
    if (!activePlan) return;
    const updatedStops = activePlan.stops.map(stop => 
      stop.id === stopId ? { ...stop, ...updates } : stop
    );
    setActivePlan({ ...activePlan, stops: updatedStops });

    if (activePlan.isSaved) {
       const updatedSaved = savedRoutes.map(r => r.id === activePlan.id ? { ...activePlan, stops: updatedStops } : r);
       setSavedRoutes(updatedSaved);
    }
  };

  const handleUpdatePlanStops = (newStops: CanvasStop[]) => {
    if (!activePlan) return;
    const newPlan = { ...activePlan, stops: newStops };
    setActivePlan(newPlan);

    if (activePlan.isSaved) {
       const updatedSaved = savedRoutes.map(r => r.id === activePlan.id ? newPlan : r);
       setSavedRoutes(updatedSaved);
    }
  };

  const handleSaveRoute = () => {
    if (!activePlan) return;
    if (activePlan.isSaved) return;

    const savedPlan = { ...activePlan, isSaved: true };
    setActivePlan(savedPlan);
    setSavedRoutes([savedPlan, ...savedRoutes]);
  };

  const handleDeleteActive = () => {
    if (window.confirm("Hapus rencana aktif ini?")) {
      setActivePlan(null);
    }
  };

  const handleBackFromActive = () => {
    if (!activePlan) {
      setActivePlan(null);
      return;
    }
    if (activePlan.isSaved) {
      setActivePlan(null);
      return;
    }
    const hasInteractions = activePlan.stops.some(stop => stop.status !== 'pending' || stop.notes);
    if (hasInteractions) {
      if (window.confirm("Simpan rute ini sebelum kembali? (Cancel untuk buang)")) {
         handleSaveRoute();
         setActivePlan(null);
      } else {
        setActivePlan(null);
      }
    } else {
      setActivePlan(null);
    }
  };

  const handleCompleteRun = () => {
    if (!activePlan) return;

    const unvisitedSelected = activePlan.stops.filter(s => s.selected && s.status === 'pending').length;

    if (unvisitedSelected > 0) {
      if (!window.confirm(`Anda masih memiliki ${unvisitedSelected} target kunjungan yang belum didatangi. Selesaikan sesi ini?`)) {
        return;
      }
    } else {
      if (!window.confirm("Selesaikan sesi canvassing ini dan simpan ke history?")) {
        return;
      }
    }

    const newHistory = [activePlan, ...history];
    setHistory(newHistory);
    if (activePlan.isSaved) {
      setSavedRoutes(savedRoutes.filter(r => r.id !== activePlan.id));
    }
    setActivePlan(null);
    setCurrentView('history');
  };

  const handleClearHistory = () => {
     if(window.confirm("Clear all history?")) {
        setHistory([]);
     }
  };

  const handleClearSaved = () => {
    if(window.confirm("Clear all saved routes?")) {
       setSavedRoutes([]);
    }
  };

  const resumeSavedRoute = (plan: CanvasPlan) => {
     if (activePlan && !activePlan.isSaved && activePlan.stops.some(s => s.status !== 'pending')) {
        if(!window.confirm("Rute aktif saat ini belum tersimpan. Ganti dengan rute tersimpan?")) {
           return;
        }
     }
     setActivePlan(plan);
     window.scrollTo(0,0);
  };

  const deleteSavedRoute = (e: React.MouseEvent, id: string) => {
    e.preventDefault();
    e.stopPropagation();
    if(window.confirm("Hapus rute tersimpan ini permanen?")) {
       setSavedRoutes(savedRoutes.filter(r => r.id !== id));
    }
  };

  const resetToHome = () => {
     if (activePlan && !activePlan.isSaved) {
        if(!window.confirm("Kembali ke menu awal? Rute aktif yang belum disimpan akan hilang.")) return;
     }
     setActivePlan(null);
     setCurrentView('active');
  };

  const getIcon = (iconName: string) => {
    switch (iconName) {
      case 'building': return <Building2 className="w-5 h-5" />;
      case 'factory': return <Factory className="w-5 h-5" />;
      case 'zap': return <Zap className="w-5 h-5" />;
      case 'coffee': return <Coffee className="w-5 h-5" />;
      case 'users': return <Users className="w-5 h-5" />;
      case 'school': return <GraduationCap className="w-5 h-5" />;
      case 'health': return <Stethoscope className="w-5 h-5" />;
      default: return <Briefcase className="w-5 h-5" />;
    }
  };

  // Render Logic
  const renderContent = () => {
    // 1. Viewing a specific history item
    if (selectedHistoryPlan) {
      return (
        <div className="animate-fade-in">
          <button 
            onClick={() => setSelectedHistoryPlan(null)}
            className="mb-4 flex items-center gap-2 text-sm font-semibold text-slate-500 dark:text-slate-400 hover:text-brand-600 dark:hover:text-brand-400"
          >
            <ArrowLeft className="w-4 h-4" /> Back to History
          </button>
          <PlanDisplay 
            plan={selectedHistoryPlan} 
            onUpdateStop={() => {}} 
            onUpdatePlanStops={() => {}}
            onComplete={() => {}} 
            onDelete={() => {}}
            readOnly={true} 
            userLocation={location || undefined}
          />
        </div>
      );
    }

    // 2. Settings View
    if (currentView === 'settings') {
       return <SettingsView onClearHistory={handleClearHistory} onClearSaved={handleClearSaved} />;
    }

    // 3. Main Active/Create View
    if (currentView === 'active') {
      if (generating) return <LoadingState />;

      if (activePlan) {
        return (
          <PlanDisplay 
            plan={activePlan} 
            onUpdateStop={handleUpdateStop}
            onUpdatePlanStops={handleUpdatePlanStops}
            onComplete={handleCompleteRun}
            onDelete={handleDeleteActive}
            onSave={handleSaveRoute}
            onBack={handleBackFromActive}
            readOnly={false}
            userLocation={location || undefined}
          />
        );
      }

      // Create New Route View (HOME)
      return (
        <div className="animate-slide-up duration-500 pb-20">

          {/* Hero Section */}
          <div className="mb-8 pt-4">
            <h2 className="text-3xl font-extrabold text-slate-900 dark:text-white mb-2 leading-tight">
              Ready to <br />
              <span className="text-brand-600 dark:text-brand-400">Hunt Leads?</span>
            </h2>
            <p className="text-slate-500 dark:text-slate-400 text-sm">
              AI-powered routing to maximize your sales visits.
            </p>
          </div>

          {/* Location Card */}
          <div className="bg-white dark:bg-slate-800 p-4 rounded-3xl shadow-sm border border-slate-200 dark:border-slate-700 mb-6 flex items-center justify-between transition-colors duration-300">
            <div className="flex items-center gap-3.5">
              <div className={`p-2.5 rounded-2xl ${locError ? 'bg-red-100 text-red-600' : 'bg-brand-50 dark:bg-brand-900/30 text-brand-600 dark:text-brand-400'}`}>
                {locError ? <AlertTriangle className="w-5 h-5" /> : <MapPin className="w-5 h-5" />}
              </div>
              <div>
                <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-wider">Current Location</p>
                {loadingLoc ? (
                  <div className="h-4 w-24 bg-slate-100 dark:bg-slate-700 rounded animate-pulse mt-1"></div>
                ) : locError ? (
                  <p className="text-sm text-red-600 font-bold">Check Permissions</p>
                ) : (
                  <p className="text-sm font-bold text-slate-800 dark:text-slate-200 font-mono">
                    {location?.lat.toFixed(4)}, {location?.lng.toFixed(4)}
                  </p>
                )}
              </div>
            </div>
            {!loadingLoc && (
              <button 
                onClick={fetchLocation}
                className="p-2 text-slate-400 hover:text-brand-600 dark:hover:text-brand-400 hover:bg-slate-50 dark:hover:bg-slate-700 rounded-xl transition-colors"
              >
                <RefreshCw className="w-5 h-5" />
              </button>
            )}
          </div>

          {/* Target Selection */}
          <div className="mb-6">
             <div className="flex items-center justify-between mb-3 px-1">
               <label className="text-sm font-bold text-slate-800 dark:text-white flex items-center gap-2">
                  Target Industry
               </label>
               {customSearchTerm && (
                  <span className="text-[10px] font-bold text-brand-600 dark:text-brand-400 bg-brand-50 dark:bg-brand-900/30 px-2 py-0.5 rounded-md animate-pulse">
                    Custom Mode
                  </span>
               )}
             </div>

             {/* Custom Search Input */}
             <div className="mb-4 relative group">
                <input 
                  type="text"
                  value={customSearchTerm}
                  onChange={(e) => {
                     setCustomSearchTerm(e.target.value);
                  }}
                  placeholder="e.g. 'Coffee Shop', 'Material Store'"
                  className="w-full pl-11 pr-4 py-3.5 rounded-2xl bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 focus:border-brand-500 dark:focus:border-brand-500 focus:ring-4 focus:ring-brand-500/10 outline-none text-sm font-medium text-slate-800 dark:text-white transition-all placeholder:text-slate-400 dark:placeholder:text-slate-500 shadow-sm"
                />
                <Search className="w-5 h-5 text-slate-400 absolute left-4 top-3.5 group-focus-within:text-brand-500 transition-colors" />
             </div>

             {/* Grid Options */}
             <div className="grid grid-cols-4 gap-2">
                {INDUSTRY_OPTIONS.map((opt) => (
                  <button
                    key={opt.id}
                    onClick={() => {
                       setSelectedIndustry(opt);
                       setCustomSearchTerm(''); 
                    }}
                    className={`flex flex-col items-center justify-center p-2.5 py-3.5 rounded-2xl border transition-all duration-200 gap-2 text-center relative ${
                      selectedIndustry.id === opt.id && !customSearchTerm
                        ? 'bg-brand-600 text-white border-brand-600 shadow-lg shadow-brand-500/30 scale-[1.02]'
                        : customSearchTerm 
                           ? 'bg-white dark:bg-slate-800 border-slate-100 dark:border-slate-700 text-slate-300 dark:text-slate-600'
                           : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-500 dark:text-slate-400 hover:border-brand-300 dark:hover:border-slate-600'
                    }`}
                  >
                    <div className={selectedIndustry.id === opt.id && !customSearchTerm ? 'text-white' : 'currentColor'}>
                      {getIcon(opt.icon)}
                    </div>
                    <span className="text-[10px] font-bold leading-tight truncate w-full">
                      {opt.label}
                    </span>
                  </button>
                ))}
             </div>
          </div>

          <button
            onClick={handleGenerate}
            disabled={generating || !!locError || !location}
            className="w-full py-4 bg-brand-600 hover:bg-brand-700 active:bg-brand-800 text-white rounded-2xl font-bold text-lg shadow-xl shadow-brand-500/30 transition-all disabled:opacity-50 disabled:shadow-none disabled:cursor-not-allowed flex items-center justify-center gap-2 transform active:scale-[0.98]"
          >
            {locError ? 'Enable Location' : 'Generate Mission'}
            {!locError && <Command className="w-5 h-5" />}
          </button>

          {/* Saved Routes Section */}
          {savedRoutes.length > 0 && (
            <div className="mt-8">
               <div className="flex items-center gap-2 mb-3 px-1">
                 <FolderOpen className="w-4 h-4 text-slate-400" />
                 <h3 className="font-bold text-sm text-slate-500 dark:text-slate-400 uppercase tracking-wider">Drafts</h3>
               </div>

               <div className="space-y-3">
                  {savedRoutes.map(route => (
                     <div key={route.id} onClick={() => resumeSavedRoute(route)} className="bg-white dark:bg-slate-800 p-4 rounded-2xl border border-slate-200 dark:border-slate-700 hover:border-brand-300 dark:hover:border-brand-700 cursor-pointer flex justify-between items-center group relative shadow-sm transition-all">
                        <div className="flex items-center gap-3">
                           <div className="w-10 h-10 rounded-full bg-slate-50 dark:bg-slate-700 flex items-center justify-center text-slate-500 dark:text-slate-400">
                              <Target className="w-5 h-5" />
                           </div>
                           <div>
                              <h4 className="font-bold text-sm text-slate-800 dark:text-slate-200">
                                 {route.customQuery || route.industry.label}
                              </h4>
                              <p className="text-xs text-slate-400 dark:text-slate-500 font-medium">{new Date(route.timestamp).toLocaleDateString()} • {route.stops.length} leads</p>
                           </div>
                        </div>
                        <div className="flex items-center gap-2">
                           <button 
                              onClick={(e) => deleteSavedRoute(e, route.id)} 
                              className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-all z-10"
                           >
                              <Trash2 className="w-4 h-4" />
                           </button>
                           <ArrowRight className="w-4 h-4 text-slate-300 group-hover:text-brand-500 dark:group-hover:text-brand-400" />
                        </div>
                     </div>
                  ))}
               </div>
            </div>
          )}
        </div>
      );
    }

    // 4. History List View
    if (currentView === 'history') {
      return (
        <HistoryView 
          history={history} 
          onSelectPlan={setSelectedHistoryPlan} 
        />
      );
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-dark-bg font-sans text-slate-900 dark:text-dark-text transition-colors duration-300">
      {/* Header */}
      <header className="fixed top-0 left-0 right-0 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-slate-200 dark:border-slate-800 z-40 transition-colors duration-300">
        <div className="max-w-2xl mx-auto px-4 h-16 flex items-center justify-between">
          <button 
            onClick={resetToHome}
            className="flex items-center gap-2.5 hover:opacity-80 transition-opacity"
            title="Reset"
          >
            <div className="bg-brand-600 text-white p-1.5 rounded-xl shadow-lg shadow-brand-500/30">
              <MapPin className="w-5 h-5" />
            </div>
            <h1 className="font-extrabold text-xl tracking-tight text-slate-900 dark:text-white">
              Canvas<span className="text-brand-600 dark:text-brand-500">Pro</span>
            </h1>
          </button>

          {activePlan && currentView === 'active' && !generating && (
            <div className="text-[10px] font-bold bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400 px-3 py-1 rounded-full border border-green-200 dark:border-green-900/50 flex items-center gap-1.5 uppercase tracking-wide">
              <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]"></div>
              Live
            </div>
          )}
        </div>
      </header>

      <main className="max-w-2xl mx-auto px-4 py-6 pt-24">
        {error && (
           <div className="mb-6 p-4 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 rounded-2xl border border-red-100 dark:border-red-900/30 text-center text-sm font-bold animate-fade-in flex items-center justify-center gap-2 shadow-sm">
            <AlertTriangle className="w-5 h-5" />
            {String(error)}
          </div>
        )}

        {renderContent()}
      </main>

      <BottomNav 
        currentView={currentView} 
        onNavigate={(view) => {
          setCurrentView(view);
          setSelectedHistoryPlan(null);
        }}
        hasActivePlan={!!activePlan}
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import ReactMarkdown from 'react-markdown';
import { CanvasPlan, CanvasStop, VisitStatus, GeoLocation } from '../types';
import { RouteMap } from './RouteMap';
import { optimizeRoute, generateGoogleMapsUrl, calculateTotalRouteDistance } from '../services/routeOptimization';
import { 
  MapPin, 
  Navigation, 
  CheckCircle2, 
  XCircle, 
  FileText, 
  ChevronDown, 
  Briefcase,
  Lightbulb,
  Archive,
  Trash2,
  ArrowLeft,
  Save,
  Map as MapIcon,
  CheckSquare,
  Share2,
  ExternalLink,
  ListTodo,
  Repeat,
  ArrowRight,
  Calendar,
  Undo2
} from 'lucide-react';

interface PlanDisplayProps {
  plan: CanvasPlan;
  onUpdateStop: (stopId: string, updates: Partial<CanvasStop>) => void;
  onUpdatePlanStops: (newStops: CanvasStop[]) => void;
  onComplete: () => void;
  onDelete: () => void;
  onSave?: () => void;
  onBack?: () => void;
  readOnly?: boolean;
  userLocation?: GeoLocation;
}

export const PlanDisplay: React.FC<PlanDisplayProps> = ({ 
  plan, 
  onUpdateStop, 
  onUpdatePlanStops,
  onComplete, 
  onDelete,
  onSave,
  onBack,
  readOnly = false,
  userLocation
}) => {
  const [activeTab, setActiveTab] = useState<'route' | 'map' | 'strategy'>('route');
  const [expandedStopId, setExpandedStopId] = useState<string | null>(null);
  const [returnToStart, setReturnToStart] = useState(false); 

  useEffect(() => {
    if (plan.stops.length === 0 && plan.markdownText) {
      setActiveTab('strategy');
    }
  }, [plan.stops.length, plan.markdownText]);

  const selectedStops = plan.stops.filter(s => s.selected);
  const completedCount = selectedStops.filter(s => s.status !== 'pending').length;
  const totalSelected = selectedStops.length;
  const totalStops = plan.stops.length;
  const progress = totalSelected > 0 ? Math.round((completedCount / totalSelected) * 100) : 0;
  const isComplete = totalSelected > 0 && completedCount === totalSelected;

  const allSelected = totalStops > 0 && totalSelected === totalStops;

  const estimatedTotalDistance = useMemo(() => {
    if (!userLocation) return 0;
    return calculateTotalRouteDistance(userLocation, selectedStops, returnToStart);
  }, [userLocation, selectedStops, returnToStart]);

  const toggleStop = (id: string) => {
    setExpandedStopId(expandedStopId === id ? null : id);
  };

  // UPDATED: Support Toggle/Undo
  const handleStatusChange = (stopId: string, newStatus: VisitStatus) => {
    if (readOnly) return;

    const stop = plan.stops.find(s => s.id === stopId);
    if (!stop) return;

    // If clicking the same status, toggle back to pending (Undo)
    const finalStatus = stop.status === newStatus ? 'pending' : newStatus;

    onUpdateStop(stopId, { status: finalStatus });
  };

  const handleNotesChange = (stopId: string, notes: string) => {
    if (readOnly) return;
    onUpdateStop(stopId, { notes });
  };

  const handleSelectionToggle = (stopId: string) => {
    if (readOnly) return;
    const stop = plan.stops.find(s => s.id === stopId);
    if (stop) {
      onUpdateStop(stopId, { selected: !stop.selected });
    }
  };

  const handleToggleAll = () => {
    if (readOnly) return;
    const newSelectionState = !allSelected;
    const newStops = plan.stops.map(stop => ({
      ...stop,
      selected: newSelectionState
    }));
    onUpdatePlanStops(newStops);
  };

  const handleOptimize = (silent = false) => {
    if (userLocation && !readOnly) {
      const optimized = optimizeRoute(userLocation, plan.stops, returnToStart);
      onUpdatePlanStops(optimized);
      if (!silent) setActiveTab('map');
      return optimized;
    }
    return plan.stops;
  };

  const handleStartSmartNavigation = () => {
    if (!userLocation) {
      alert("Lokasi Anda dibutuhkan untuk navigasi.");
      return;
    }
    if (totalSelected === 0) {
      alert("Pilih minimal satu lokasi untuk navigasi.");
      return;
    }
    const optimizedStops = handleOptimize(true); 
    const url = generateGoogleMapsUrl(userLocation, optimizedStops, returnToStart);
    if (!url) {
      alert("Gagal membuat link navigasi.");
      return;
    }
    window.open(url, '_blank');
  };

  const handleShareReport = () => {
    const date = new Date(plan.timestamp).toLocaleDateString();
    const target = plan.customQuery || plan.industry.label;

    let report = `*LAPORAN CANVAS PRO*\n`;
    report += `📅 Tanggal: ${date}\n`;
    report += `🎯 Target: ${target}\n`;
    report += `📏 Estimasi Jarak: ${estimatedTotalDistance} km (${returnToStart ? 'PP' : 'One Way'})\n`;
    report += `📊 Progress: ${completedCount}/${totalSelected} (${progress}%)\n\n`;
    report += `*DETAIL KUNJUNGAN:*\n`;

    selectedStops.forEach((stop, idx) => {
      const statusIcon = stop.status === 'visited' ? '✅' : stop.status === 'skipped' ? '⛔' : '⏳';
      report += `${idx + 1}. ${stop.title} ${statusIcon}\n`;
      if (stop.status !== 'pending' && stop.notes) {
        report += `   📝 Note: ${stop.notes}\n`;
      }
    });
    report += `\n_Generated by CanvasPro App_`;
    const url = `https://wa.me/?text=${encodeURIComponent(report)}`;
    window.open(url, '_blank');
  };

  // UPDATED: Combined Logic for "Finish & Report"
  const handleFinishAndReport = () => {
    // 1. Open WhatsApp Report
    handleShareReport();

    // 2. Trigger Completion flow after a short delay to allow the tab to open
    setTimeout(() => {
      // Use standard completion flow (which saves to history)
      onComplete(); 
    }, 1000);
  };

  return (
    // UPDATED: Increased padding bottom to prevent overlap with new higher FAB position
    <div className="animate-slide-up pb-48"> 

      {/* Dashboard Header */}
