export interface GeoLocation {
  lat: number;
  lng: number;
}

export interface PlaceSource {
  uri: string;
  title: string;
}

export interface GroundingChunk {
  maps?: {
    sourceId?: string;
    title?: string;
    uri?: string;
    placeAnswerSources?: {
      reviewSnippets?: {
        content?: string;
      }[];
    }[];
  };
}

export type VisitStatus = 'pending' | 'visited' | 'skipped';

export interface CanvasStop extends PlaceSource {
  id: string;
  status: VisitStatus;
  notes: string;
  selected: boolean; 
  lat?: number; // Optional
  lng?: number; // Optional
  distance?: number; // Distance from start in KM
}

export interface CanvasPlan {
  id: string;
  timestamp: number;
  industry: IndustryOption;
  customQuery?: string; // Added for custom search support
  markdownText: string;
  stops: CanvasStop[];
  isSaved?: boolean;
}

export type IndustryType = 'corporate' | 'industrial' | 'startup' | 'retail' | 'hospitality' | 'outsourcing' | 'education' | 'health' | 'custom';

export interface IndustryOption {
  id: IndustryType;
  label: string;
  query: string;
  icon: string;
}

import { GoogleGenAI, Tool } from "@google/genai";
import { GeoLocation, CanvasPlan, PlaceSource, CanvasStop, IndustryOption } from "../types";
import { calculateDistance } from "./routeOptimization";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateCanvasRoute = async (
  location: GeoLocation,
  industry: IndustryOption,
  customQueryText?: string
): Promise<CanvasPlan> => {

  // Use custom query if provided, otherwise default to industry query
  const searchContext = customQueryText || industry.query;
  const categoryLabel = customQueryText || industry.label;

  // System Instruction in Indonesian for local context
  const systemInstruction = `
    Anda adalah Sales Manager B2B senior untuk Absenku.com.
    Tugas: Cari prospek bisnis nyata menggunakan Google Maps di sekitar lokasi user.

    CRITICAL INSTRUCTION:
    1. GUNAKAN TOOL 'googleMaps' untuk mencari lokasi. Jangan hanya memberikan saran teks.
    2. Cari 8-12 bisnis yang SANGAT RELEVAN dengan kata kunci: "${searchContext}".
    3. Filter: Prioritaskan bisnis yang memiliki kantor fisik atau operasional nyata.
    4. Berikan output teks dalam format Markdown yang berisi:
       - **Alasan**: Kenapa bisnis ini butuh aplikasi HR.
       - **Opening Pitch**: Satu kalimat pembuka yang spesifik untuk jenis bisnis ini.
  `;

  try {
    const tools: Tool[] = [{ googleMaps: {} }];

    const prompt = `
      Lokasi saya: ${location.lat}, ${location.lng}.
      Saya adalah sales yang sedang mencari klien baru.

      Tolong carikan daftar: ${categoryLabel}.
      Gunakan search query spesifik: "${searchContext}".

      Pilih tempat-tempat yang potensial untuk didatangi langsung (canvas).
      Untuk setiap tempat, berikan strategi pendekatan singkat.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        systemInstruction,
        tools,
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: location.lat,
              longitude: location.lng,
            },
          },
        },
      },
    });

    const markdownText = response.text || "Tidak ada strategi khusus yang tersedia, namun lokasi telah ditemukan.";

    // Extract places from grounding chunks
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const rawPlaces: PlaceSource[] = [];

    chunks.forEach((chunk) => {
      if (chunk.maps?.uri && chunk.maps?.title) {
        rawPlaces.push({
          uri: chunk.maps.uri,
          title: chunk.maps.title,
        });
      }
    });

    // Remove duplicates based on URI
    const uniquePlaces = Array.from(new Map(rawPlaces.map(item => [item.uri, item])).values());

    // Generate a safe unique ID
    const generateId = () => {
      if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID();
      }
      return `plan-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    };

    // Transform to CanvasStop with state and ATTEMPT TO EXTRACT COORDS
    const stops: CanvasStop[] = uniquePlaces.map((place, index) => {
      let lat: number | undefined;
      let lng: number | undefined;
      let distance: number | undefined;

      // Try to extract coordinates from Google Maps URI
      // Typical format: /@(-6.123,106.123), or /@(-6.123,106.123,15z)/
      try {
        const match = place.uri.match(/@(-?\d+\.\d+),(-?\d+\.\d+)/);
        if (match) {
          lat = parseFloat(match[1]);
          lng = parseFloat(match[2]);

          // Calculate distance immediately
          distance = calculateDistance(location, { lat, lng });
        }
      } catch (e) {
        // Ignore extraction errors
      }

      return {
        ...place,
        id: `stop-${Date.now()}-${index}-${Math.random().toString(36).substr(2, 5)}`,
        status: 'pending',
        notes: '',
        selected: true,
        lat, 
        lng,
        distance
      };
    });

    // SORTING: Urutkan berdasarkan jarak terdekat
    stops.sort((a, b) => {
      // Prioritaskan yang punya jarak
      if (a.distance !== undefined && b.distance !== undefined) {
        return a.distance - b.distance;
      }
      if (a.distance !== undefined) return -1;
      if (b.distance !== undefined) return 1;
      return 0;
    });

    if (stops.length === 0 && !response.text) {
       throw new Error("AI tidak dapat menemukan lokasi spesifik di peta. Coba perluas area atau ganti kata kunci.");
    }

    return {
      id: generateId(),
      timestamp: Date.now(),
      industry,
      customQuery: customQueryText,
      markdownText,
      stops,
      isSaved: false
    };

  } catch (error: any) {
    console.error("Error generating canvas route:", error);
    const msg = error?.message || "Terjadi kesalahan saat menghubungi AI.";
    throw new Error(msg);
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import ReactMarkdown from 'react-markdown';
import { CanvasPlan, CanvasStop, VisitStatus, GeoLocation } from '../types';
import { RouteMap } from './RouteMap';
import { optimizeRoute, generateGoogleMapsUrl, calculateTotalRouteDistance } from '../services/routeOptimization';
import { 
  MapPin, 
  Navigation, 
  CheckCircle2, 
  XCircle, 
  FileText, 
  ChevronDown, 
  Briefcase,
  Lightbulb,
  Archive,
  Trash2,
  ArrowLeft,
  Save,
  Map as MapIcon,
  CheckSquare,
  Share2,
  ExternalLink,
  ListTodo,
  Repeat,
  ArrowRight,
  Calendar,
  Undo2
} from 'lucide-react';

interface PlanDisplayProps {
  plan: CanvasPlan;
  onUpdateStop: (stopId: string, updates: Partial<CanvasStop>) => void;
  onUpdatePlanStops: (newStops: CanvasStop[]) => void;
  onComplete: () => void;
  onDelete: () => void;
  onSave?: () => void;
  onBack?: () => void;
  readOnly?: boolean;
  userLocation?: GeoLocation;
}

export const PlanDisplay: React.FC<PlanDisplayProps> = ({ 
  plan, 
  onUpdateStop, 
  onUpdatePlanStops,
  onComplete, 
  onDelete,
  onSave,
  onBack,
  readOnly = false,
  userLocation
}) => {
  const [activeTab, setActiveTab] = useState<'route' | 'map' | 'strategy'>('route');
  const [expandedStopId, setExpandedStopId] = useState<string | null>(null);
  const [returnToStart, setReturnToStart] = useState(false); 

  useEffect(() => {
    if (plan.stops.length === 0 && plan.markdownText) {
      setActiveTab('strategy');
    }
  }, [plan.stops.length, plan.markdownText]);

  const selectedStops = plan.stops.filter(s => s.selected);
  const completedCount = selectedStops.filter(s => s.status !== 'pending').length;
  const totalSelected = selectedStops.length;
  const totalStops = plan.stops.length;
  const progress = totalSelected > 0 ? Math.round((completedCount / totalSelected) * 100) : 0;
  const isComplete = totalSelected > 0 && completedCount === totalSelected;

  const allSelected = totalStops > 0 && totalSelected === totalStops;

  const estimatedTotalDistance = useMemo(() => {
    if (!userLocation) return 0;
    return calculateTotalRouteDistance(userLocation, selectedStops, returnToStart);
  }, [userLocation, selectedStops, returnToStart]);

  const toggleStop = (id: string) => {
    setExpandedStopId(expandedStopId === id ? null : id);
  };

  // Support Toggle/Undo
  const handleStatusChange = (stopId: string, newStatus: VisitStatus) => {
    if (readOnly) return;

    const stop = plan.stops.find(s => s.id === stopId);
    if (!stop) return;

    // If clicking the same status, toggle back to pending (Undo)
    const finalStatus = stop.status === newStatus ? 'pending' : newStatus;

    onUpdateStop(stopId, { status: finalStatus });
  };

  const handleNotesChange = (stopId: string, notes: string) => {
    if (readOnly) return;
    onUpdateStop(stopId, { notes });
  };

  const handleSelectionToggle = (stopId: string) => {
    if (readOnly) return;
    const stop = plan.stops.find(s => s.id === stopId);
    if (stop) {
      onUpdateStop(stopId, { selected: !stop.selected });
    }
  };

  const handleToggleAll = () => {
    if (readOnly) return;
    const newSelectionState = !allSelected;
    const newStops = plan.stops.map(stop => ({
      ...stop,
      selected: newSelectionState
    }));
    onUpdatePlanStops(newStops);
  };

  const handleOptimize = (silent = false) => {
    if (userLocation && !readOnly) {
      const optimized = optimizeRoute(userLocation, plan.stops, returnToStart);
      onUpdatePlanStops(optimized);
      if (!silent) setActiveTab('map');
      return optimized;
    }
    return plan.stops;
  };

  const handleStartSmartNavigation = () => {
    if (!userLocation) {
      alert("Lokasi Anda dibutuhkan untuk navigasi.");
      return;
    }
    if (totalSelected === 0) {
      alert("Pilih minimal satu lokasi untuk navigasi.");
      return;
    }
    const optimizedStops = handleOptimize(true); 
    const url = generateGoogleMapsUrl(userLocation, optimizedStops, returnToStart);
    if (!url) {
      alert("Gagal membuat link navigasi.");
      return;
    }
    window.open(url, '_blank');
  };

  const handleShareReport = () => {
    const date = new Date(plan.timestamp).toLocaleDateString();
    const target = plan.customQuery || plan.industry.label;

    let report = `*LAPORAN CANVAS PRO*\n`;
    report += `📅 Tanggal: ${date}\n`;
    report += `🎯 Target: ${target}\n`;
    report += `📏 Estimasi Jarak: ${estimatedTotalDistance} km (${returnToStart ? 'PP' : 'One Way'})\n`;
    report += `📊 Progress: ${completedCount}/${totalSelected} (${progress}%)\n\n`;
    report += `*DETAIL KUNJUNGAN:*\n`;

    selectedStops.forEach((stop, idx) => {
      const statusIcon = stop.status === 'visited' ? '✅' : stop.status === 'skipped' ? '⛔' : '⏳';
      report += `${idx + 1}. ${stop.title} ${statusIcon}\n`;
      if (stop.status !== 'pending' && stop.notes) {
        report += `   📝 Note: ${stop.notes}\n`;
      }
    });
    report += `\n_Generated by CanvasPro App_`;
    const url = `https://wa.me/?text=${encodeURIComponent(report)}`;
    window.open(url, '_blank');
  };

  const handleFinishAndReport = () => {
    handleShareReport();
    setTimeout(() => {
      onComplete(); 
    }, 1000);
  };

  return (
    <div className="animate-slide-up pb-48"> 

      {/* Dashboard Header */}
      <div className="bg-white dark:bg-slate-800 rounded-3xl p-5 shadow-sm border border-slate-200 dark:border-slate-700 mb-6 transition-colors duration-300">
        <div className="flex flex-col gap-4 mb-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              {!readOnly && onBack && (
                <button 
                  onClick={onBack}
                  className="p-2 -ml-2 text-slate-400 dark:text-slate-500 hover:text-brand-600 dark:hover:text-brand-400 hover:bg-slate-50 dark:hover:bg-slate-700 rounded-full transition-colors"
                >
                  <ArrowLeft className="w-6 h-6" />
                </button>
              )}
              <div>
                <h2 className="text-xl font-extrabold text-slate-900 dark:text-white leading-tight">
                  {plan.customQuery ? `"${plan.customQuery}"` : plan.industry?.label}
                </h2>
                <div className="flex items-center gap-2 mt-1">
                  <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-md bg-slate-100 dark:bg-slate-700/50">
                    <Calendar className="w-3 h-3 text-slate-400" />
                    <span className="text-xs font-medium text-slate-500 dark:text-slate-400">
                      {new Date(plan.timestamp).toLocaleDateString()}
                    </span>
                  </div>
                  {plan.isSaved && (
                    <span className="text-brand-600 dark:text-brand-400 bg-brand-50 dark:bg-brand-900/30 px-2 py-0.5 rounded-md font-bold text-[10px] uppercase border border-brand-100 dark:border-brand-800">
                      Saved
                    </span>
                  )}
                </div>
              </div>
            </div>

             {readOnly && (
               <button 
                 onClick={handleShareReport}
                 className="p-2.5 bg-green-50 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded-xl hover:bg-green-100 dark:hover:bg-green-900/50 transition-colors"
                 title="Share Report via WhatsApp"
               >
                 <Share2 className="w-5 h-5" />
               </button>
            )}
          </div>

          {!readOnly && (
            <div className="flex gap-2 justify-between items-center border-t border-slate-50 dark:border-slate-700 pt-3">
               <div className="flex gap-2">
                <button 
                  onClick={onDelete}
                  className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors flex items-center gap-1 text-xs font-medium"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
               </div>

               <div className="flex gap-2">
                  {onSave && !plan.isSaved && (
                    <button 
                      onClick={onSave}
                      className="flex items-center gap-1.5 px-3 py-2 bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 text-slate-600 dark:text-slate-200 text-xs font-bold rounded-lg hover:border-brand-300 hover:text-brand-600 dark:hover:text-brand-300 transition-colors shadow-sm"
                    >
                      <Save className="w-4 h-4" />
                      Save Draft
                    </button>
                  )}
                  <button 
                    onClick={isComplete ? handleFinishAndReport : onComplete}
                    className={`flex items-center gap-1.5 px-4 py-2 text-xs font-bold rounded-lg shadow-sm transition-all ${
                      isComplete 
                        ? 'bg-green-600 dark:bg-green-700 text-white hover:bg-green-700 shadow-green-200 dark:shadow-none animate-pulse' 
                        : 'bg-brand-600 dark:bg-brand-700 text-white hover:bg-brand-700 shadow-brand-200 dark:shadow-none'
                    }`}
                  >
                    <Archive className="w-4 h-4" />
                    {isComplete ? 'Finish & Report' : 'Finish'}
                  </button>
               </div>
            </div>
          )}
        </div>

        <div className="space-y-2">
          <div className="flex justify-between text-sm font-medium">
            <span className="text-slate-600 dark:text-slate-400 text-xs uppercase tracking-wide font-bold">Progress</span>
            <span className={isComplete ? "text-green-600 dark:text-green-400 font-bold" : "text-brand-700 dark:text-brand-400 font-bold"}>
              {completedCount}/{totalSelected} <span className="text-xs text-slate-400 dark:text-slate-500 font-normal">Leads</span>
            </span>
          </div>
          <div className="h-3 w-full bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden relative shadow-inner">
            <div 
              className={`h-full transition-all duration-700 cubic-bezier(0.4, 0, 0.2, 1) relative ${readOnly ? 'bg-slate-400' : isComplete ? 'bg-green-500' : 'bg-brand-500'}`}
              style={{ width: `${progress}%` }}
            >
              <div className="absolute top-0 left-0 bottom-0 right-0 bg-gradient-to-r from-transparent via-white/20 to-transparent animate-[shimmer_2s_infinite] -skew-x-12"></div>
            </div>
          </div>
        </div>
      </div>

      <div className="flex p-1.5 bg-white dark:bg-slate-800 rounded-2xl mb-6 shadow-sm border border-slate-100 dark:border-slate-700 sticky top-20 z-30 transition-colors duration-300">
        <button
          onClick={() => setActiveTab('route')}
          className={`flex-1 py-2.5 text-xs font-bold rounded-xl flex items-center justify-center gap-2 transition-all duration-300 ${
            activeTab === 'route' 
              ? 'bg-brand-50 dark:bg-brand-900/30 text-brand-700 dark:text-brand-400 shadow-sm ring-1 ring-brand-200 dark:ring-brand-800' 
              : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-300'
          }`}
        >
          <ListTodo className="w-4 h-4" />
          Task List
        </button>
        <button
          onClick={() => setActiveTab('map')}
          className={`flex-1 py-2.5 text-xs font-bold rounded-xl flex items-center justify-center gap-2 transition-all duration-300 ${
            activeTab === 'map' 
              ? 'bg-brand-50 dark:bg-brand-900/30 text-brand-700 dark:text-brand-400 shadow-sm ring-1 ring-brand-200 dark:ring-brand-800' 
              : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-300'
          }`}
        >
          <MapIcon className="w-4 h-4" />
          Blueprint
        </button>
        <button
          onClick={() => setActiveTab('strategy')}
          className={`flex-1 py-2.5 text-xs font-bold rounded-xl flex items-center justify-center gap-2 transition-all duration-300 ${
            activeTab === 'strategy' 
              ? 'bg-brand-50 dark:bg-brand-900/30 text-brand-700 dark:text-brand-400 shadow-sm ring-1 ring-brand-200 dark:ring-brand-800' 
              : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-300'
          }`}
        >
          <Lightbulb className="w-4 h-4" />
          Briefing
        </button>
      </div>

      {activeTab === 'strategy' && (
        <div className="bg-white dark:bg-slate-800 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-700 animate-slide-up transition-colors duration-300">
          <div className="flex items-center gap-3 mb-6 pb-4 border-b border-slate-100 dark:border-slate-700">
             <div className="bg-amber-100 dark:bg-amber-900/30 p-2.5 rounded-xl text-amber-600 dark:text-amber-400 shadow-sm">
                <Lightbulb className="w-6 h-6" />
             </div>
             <div>
                <h3 className="font-bold text-lg text-slate-800 dark:text-slate-200">AI Sales Briefing</h3>
                <p className="text-xs text-slate-500 dark:text-slate-400 font-medium">Strategi pendekatan khusus untuk kategori ini</p>
             </div>
          </div>
          <div className="prose prose-slate dark:prose-invert prose-sm prose-headings:text-brand-700 dark:prose-headings:text-brand-400 prose-a:text-brand-600 max-w-none">
            <ReactMarkdown>{String(plan.markdownText || 'Tidak ada briefing tersedia.')}</ReactMarkdown>
          </div>
        </div>
