import React, { useState, useMemo } from 'react';
import { CanvasStop, GeoLocation } from '../types';
import { generateMockCoordinates, calculateDistance } from '../services/routeOptimization';
import { MapPin, Navigation, Compass, ExternalLink, Ruler } from 'lucide-react';

interface RouteMapProps {
  stops: CanvasStop[];
  userLocation: GeoLocation;
  returnToStart?: boolean;
}

export const RouteMap: React.FC<RouteMapProps> = ({ stops, userLocation, returnToStart = false }) => {
  const [selectedPointId, setSelectedPointId] = useState<string | null>(null);

  // Filter active stops
  const activeStops = stops.filter(s => s.selected);

  // Prepare points with valid coordinates and status info
  const points = useMemo(() => {
    return [
      { 
        id: 'start', 
        lat: userLocation.lat, 
        lng: userLocation.lng, 
        label: 'S', 
        title: 'Lokasi Anda (Start)', 
        isStart: true,
        status: 'visited', // Start is always visited
        notes: ''
      },
      ...activeStops.map((stop, i) => {
        const hasCoords = typeof stop.lat === 'number' && typeof stop.lng === 'number';
        const coords = hasCoords
          ? { lat: stop.lat!, lng: stop.lng! }
          : generateMockCoordinates(userLocation, i, activeStops.length);

        return { 
          id: stop.id, 
          lat: coords.lat,
          lng: coords.lng,
          label: String(i + 1),
          title: stop.title,
          isStart: false,
          status: stop.status,
          uri: stop.uri,
          notes: stop.notes
        };
      })
    ];
  }, [activeStops, userLocation]);

  // Handle empty state
  if (activeStops.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-64 bg-slate-50 dark:bg-slate-800 rounded-2xl border border-dashed border-slate-300 dark:border-slate-700">
        <MapPin className="w-8 h-8 text-slate-300 mb-2" />
        <p className="text-slate-400 text-sm">Pilih lokasi untuk melihat rute</p>
      </div>
    );
  }

  // --- Normalization Logic ---
  const lats = points.map(p => p.lat);
  const lngs = points.map(p => p.lng);
  const minLat = Math.min(...lats);
  const maxLat = Math.max(...lats);
  const minLng = Math.min(...lngs);
  const maxLng = Math.max(...lngs);

  // Calculate real world dimensions for Scale Bar
  const heightKm = calculateDistance({ lat: minLat, lng: minLng }, { lat: maxLat, lng: minLng });
  const widthKm = calculateDistance({ lat: minLat, lng: minLng }, { lat: minLat, lng: maxLng });
  const maxDimensionKm = Math.max(heightKm, widthKm);

  // Scale Bar Text Logic
  let scaleText = "";
  let scaleWidthPercent = 0.2; // Default 20% of map width

  if (maxDimensionKm < 1) {
     scaleText = `${Math.round(maxDimensionKm * 1000 * 0.2)} m`; // Show meters if small area
  } else {
     scaleText = `${(maxDimensionKm * 0.2).toFixed(1)} km`;
  }


  // Add padding
  const latSpan = maxLat - minLat || 0.002;
  const lngSpan = maxLng - minLng || 0.002;
  const paddingLat = latSpan * 0.2; // 20% padding
  const paddingLng = lngSpan * 0.2;

  // Aspect Ratio
  const aspectRatio = (lngSpan + 2 * paddingLng) / (latSpan + 2 * paddingLat);
  const svgHeight = 350;
  const svgWidth = svgHeight * aspectRatio;

  const normalize = (lat: number, lng: number) => {
    const x = ((lng - (minLng - paddingLng)) / (lngSpan + 2 * paddingLng)) * svgWidth;
    const y = svgHeight - (((lat - (minLat - paddingLat)) / (latSpan + 2 * paddingLat)) * svgHeight);
    return { x, y };
  };

  const normalizedPoints = points.map(p => ({
    ...p,
    ...normalize(p.lat, p.lng)
  }));

  // --- Generate Segments for Coloring ---
  const segments = [];
  for (let i = 0; i < normalizedPoints.length - 1; i++) {
    const start = normalizedPoints[i];
    const end = normalizedPoints[i + 1];

    // Logic color: If destination (end) is visited, line is green (completed path)
    // If skipped, red/grey. Else pending (dashed).
    let type = 'pending';
    if (end.status === 'visited') type = 'visited';
    if (end.status === 'skipped') type = 'skipped';

    segments.push({ start, end, type });
  }

  if (returnToStart && normalizedPoints.length > 1) {
     segments.push({
        start: normalizedPoints[normalizedPoints.length - 1],
        end: normalizedPoints[0],
        type: 'pending' // Return trip is usually pending until done
     });
  }

  const handlePointClick = (id: string) => {
    setSelectedPointId(selectedPointId === id ? null : id);
  };

  const selectedPointData = normalizedPoints.find(p => p.id === selectedPointId);

  return (
    <div className="relative w-full bg-slate-50 dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-700 overflow-hidden shadow-inner group select-none">

      {/* Grid Background */}
      <div className="absolute inset-0 opacity-[0.07] dark:opacity-[0.1]" 
           style={{ 
             backgroundImage: 'linear-gradient(#64748b 1px, transparent 1px), linear-gradient(90deg, #64748b 1px, transparent 1px)', 
             backgroundSize: '40px 40px' 
           }}>
      </div>

      {/* Header Info */}
      <div className="absolute top-3 left-3 flex gap-2 z-10">
        <div className="bg-white/90 dark:bg-slate-800/90 backdrop-blur border border-slate-200 dark:border-slate-600 px-2.5 py-1.5 rounded-lg shadow-sm flex items-center gap-1.5">
          <Compass className="w-3.5 h-3.5 text-brand-500" />
          <span className="text-[10px] font-bold text-slate-600 dark:text-slate-300">
            TACTICAL MAP
          </span>
        </div>
      </div>

      <div className="w-full overflow-x-auto overflow-y-hidden custom-scrollbar touch-pan-x">
        <svg 
          height={svgHeight} 
          width={svgWidth} 
          className="mx-auto my-4"
          style={{ minWidth: '100%' }}
        >
          <defs>
            <marker id="arrow-pending" markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto">
              <path d="M0,0 L0,6 L6,3 z" fill="#94a3b8" />
            </marker>
             <marker id="arrow-visited" markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto">
              <path d="M0,0 L0,6 L6,3 z" fill="#22c55e" />
            </marker>
