                  className="shadow-sm"
                />

                {/* Label inside circle */}
                <text 
                  x={p.x} y={p.y} 
                  dy=".3em" 
                  textAnchor="middle" 
                  fontSize="3.5" 
                  fontWeight="bold" 
                  fill="white"
                >
                  {p.label}
                </text>
              </g>
            );
          })}
        </svg>
      </div>

      {/* Scale Bar */}
      <div className="absolute bottom-12 right-4 flex flex-col items-end pointer-events-none">
          <div className="flex items-center gap-1 text-[10px] text-slate-400 font-mono mb-1">
